    <script>
        const canvas = document.getElementById('fireworks-canvas');
        const ctx = canvas.getContext('2d');
        let fireworks = [];
        let particles = [];

        function setupCanvas() {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        }
        setupCanvas();
        window.addEventListener('resize', setupCanvas);

        function Firework(sx, sy, tx, ty) {
            this.x = sx;
            this.y = sy;
            this.sx = sx;
            this.sy = sy;
            this.tx = tx;
            this.ty = ty;
            this.distanceToTarget = Math.sqrt(Math.pow(tx - sx, 2) + Math.pow(ty - sy, 2));
            this.distanceTraveled = 0;
            this.coordinates = [];
            this.coordinateCount = 3;
            while(this.coordinateCount--) {
                this.coordinates.push([this.x, this.y]);
            }
            this.angle = Math.atan2(ty - sy, tx - sx);
            this.speed = 2;
            this.acceleration = 1.05;
            this.brightness = Math.random() * 20 + 50;
            this.targetRadius = 1;
        }

        Firework.prototype.update = function(index) {
            this.coordinates.pop();
            this.coordinates.unshift([this.x, this.y]);
            this.speed *= this.acceleration;
            let vx = Math.cos(this.angle) * this.speed;
            let vy = Math.sin(this.angle) * this.speed;
            this.distanceTraveled = Math.sqrt(Math.pow(this.x - this.sx, 2) + Math.pow(this.y - this.sy, 2));
            if(this.distanceTraveled >= this.distanceToTarget) {
                createParticles(this.tx, this.ty);
                fireworks.splice(index, 1);
            } else {
                this.x += vx;
                this.y += vy;
            }
        }

        Firework.prototype.draw = function() {
            ctx.beginPath();
            ctx.moveTo(this.coordinates[this.coordinates.length - 1][0], this.coordinates[this.coordinates.length - 1][1]);
            ctx.lineTo(this.x, this.y);
            ctx.strokeStyle = `hsl(${180 + Math.random() * 60}, 100%, ${this.brightness}%)`;
            ctx.stroke();
        }

        function Particle(x, y) {
            this.x = x;
            this.y = y;
            this.coordinates = [];
            this.coordinateCount = 5;
            while(this.coordinateCount--) {
                this.coordinates.push([this.x, this.y]);
            }
            this.angle = Math.random() * (Math.PI * 2);
            this.speed = Math.random() * 5 + 1;
            this.friction = 0.95;
            this.gravity = 1;
            this.hue = 180 + Math.random() * 60;
            this.brightness = Math.random() * 30 + 50;
            this.alpha = 1;
            this.decay = Math.random() * 0.03 + 0.015;
        }

        Particle.prototype.update = function(index) {
            this.coordinates.pop();
            this.coordinates.unshift([this.x, this.y]);
            this.speed *= this.friction;
            this.x += Math.cos(this.angle) * this.speed;
            this.y += Math.sin(this.angle) * this.speed + this.gravity;
            this.alpha -= this.decay;
            if(this.alpha <= this.decay) {
                particles.splice(index, 1);
            }
        }

        Particle.prototype.draw = function() {
            ctx.beginPath();
            ctx.moveTo(this.coordinates[this.coordinates.length - 1][0], this.coordinates[this.coordinates.length - 1][1]);
            ctx.lineTo(this.x, this.y);
            ctx.strokeStyle = `hsla(${this.hue}, 100%, ${this.brightness}%, ${this.alpha})`;
            ctx.stroke();
        }

        function createParticles(x, y) {
            let particleCount = 100;
            while(particleCount--) {
                particles.push(new Particle(x, y));
            }
        }

        let launchInterval = 200;
        let lastLaunch = new Date().getTime();

        function loop() {
            requestAnimationFrame(loop);
            ctx.globalCompositeOperation = 'destination-out';
            ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.globalCompositeOperation = 'lighter';

            let i = fireworks.length;
            while(i--) {
                fireworks[i].draw();
                fireworks[i].update(i);
            }

            let j = particles.length;
            while(j--) {
                particles[j].draw();
                particles[j].update(j);
            }

            let now = new Date().getTime();
            if(now - lastLaunch > launchInterval) {
                fireworks.push(new Firework(canvas.width/2, canvas.height, Math.random() * canvas.width, Math.random() * canvas.height / 2));
                lastLaunch = now;
            }
        }
        loop();

        const card = document.getElementById('info-card');
        const sensitivity = 20;

        card.addEventListener('mousemove', (e) => {
            const { clientX, clientY } = e;
            const { left, top, width, height } = card.getBoundingClientRect();

            const x = clientX - left;
            const y = clientY - top;

            const rotateY = sensitivity * ((x - width / 2) / width);
            const rotateX = -sensitivity * ((y - height / 2) / height);

            card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`;
        });

        card.addEventListener('mouseleave', () => {
            card.style.transform = 'perspective(1000px) rotateX(0deg) rotateY(0deg)';
        });

        async function switchToSecondGreeting() {
            if (typeof getChatMessages !== 'undefined' && typeof setChatMessage !== 'undefined') {
                try {
                    const msgs = await getChatMessages(0, { include_swipe: true });

                    if (msgs && msgs[0] && msgs[0].swipes && msgs[0].swipes.length > 1) {
                        const targetSwipeContent = msgs[0].swipes[1];

                        setChatMessage(targetSwipeContent, 0, {
                            swipe_id: 1,
                            refresh: 'display_and_render_current'
                        });

                    } else {
                        alert('当前未检测到第二个开场白。请确保你已配置了 Alternate Greetings 选项。');
                    }
                } catch (err) {
                    console.error(err);
                    alert('灵力流转受阻，仙途开启失败，请查看控制台报错。');
                }
            } else if (typeof triggerSlash !== 'undefined') {
                triggerSlash('/send 开启仙途');
            } else {
                alert('当前环境如同无法吸纳灵气的虚空，未检测到任何助手指令哦~');
            }
        }
    </script>
</body>
</html>
