    function drawMap(loreData, containerId) {
        const mapContainer = document.getElementById(containerId);
        if (!mapContainer) return;

        const connections = [
            ['center', 'north'], ['center', 'south'], ['center', 'east'], ['center', 'west']
        ];

        if (loreData['special_east']) {
            connections.push(['east', 'special_east']);
        }
        if (loreData['s_youlin']) {
            connections.push(['south', 's_youlin']);
            connections.push(['west', 's_gengjin']);
            connections.push(['north', 's_liuli']);
            connections.push(['center', 's_wuxing']);
            connections.push(['west', 's_shahai']);
            connections.push(['east', 's_yunsheng']);
            connections.push(['south', 's_huangquan']);
            connections.push(['center', 's_tianyuan']);
        }

        connections.forEach(([k1, k2]) => {
            if(!loreData[k1] || !loreData[k2]) return;
            const n1 = loreData[k1];
            const n2 = loreData[k2];
            const line = document.createElement('div');
            line.className = 'map-line';

            const dx = n2.x - n1.x;
            const dy = n2.y - n1.y;
            const dist = Math.sqrt(dx*dx + dy*dy);
            const angle = Math.atan2(dy, dx) * 180 / Math.PI;

            line.style.width = `calc(${dist}% - 10px)`;
            line.style.left = `${n1.x}%`;
            line.style.top = `${n1.y}%`;
            line.style.transform = `rotate(${angle}deg)`;
            mapContainer.appendChild(line);
        });

        Object.entries(loreData).forEach(([key, data]) => {
            const node = document.createElement('div');
            let nodeClass = 'map-node';
            if(key === 'center') nodeClass += ' node-center';
            else if(key === 'north') nodeClass += ' node-north';
            else if(key === 'south') nodeClass += ' node-south';
            else if(key === 'east') nodeClass += ' node-east';
            else if(key === 'west') nodeClass += ' node-west';
            else nodeClass += ' node-special';

            node.className = nodeClass;
            node.style.left = `${data.x}%`;
            node.style.top = `${data.y}%`;
            node.innerHTML = `<div class="map-node-label">${data.name}</div>`;

            // Node Click Interaction updated to toggle active states & trigger scroll
            node.onclick = () => {
                document.querySelectorAll(`.map-node`).forEach(n => n.classList.remove('active-node'));
                node.classList.add('active-node');
                showLocationDetails(data);
            };
            mapContainer.appendChild(node);
        });
    }

    function initMap() {
        drawMap(xuantianLore, 'world-map-xuantian');
        drawMap(xianjieLore, 'world-map-xianjie');
    }

    function showLocationDetails(data) {
        const panel = document.getElementById('map-details');
        panel.classList.add('active');
        const titleEl = document.getElementById('map-loc-name');

        const colorVar = data.color.startsWith('#') ? data.color : `var(${data.color})`;
        titleEl.textContent = data.name;
        titleEl.style.color = colorVar;
        titleEl.parentElement.style.color = colorVar;

        // Apply visual cue to panel corresponding to the node's color
        const infoCard = panel.querySelector('.info-card');
        infoCard.style.borderColor = colorVar;

        document.getElementById('map-loc-type').textContent = data.realm;
        document.getElementById('map-loc-desc').innerHTML = data.desc;

        const factionsContainer = document.getElementById('map-loc-factions');
        factionsContainer.innerHTML = '';
        if(data.factions && data.factions.length > 0) {
            data.factions.forEach(fac => {
                const tag = document.createElement('span');
                let tagClass = 'faction-tag';
                if(fac.type === 'human') tagClass += ' tag-human';
                else if(fac.type === 'demon') tagClass += ' tag-demon';
                else if(fac.type === 'monster') tagClass += ' tag-monster';
                else tagClass += ' tag-neutral';

                tag.className = tagClass;
                tag.textContent = fac.name;
                tag.title = fac.note || '';

                tag.onclick = function() {
                    document.getElementById('faction-modal-title').textContent = '【' + fac.name + '】';
                    document.getElementById('faction-modal-note').textContent = fac.note || '暂无详细信息';
                    document.getElementById('faction-modal-overlay').style.display = 'flex';
                };

                factionsContainer.appendChild(tag);
            });
        } else {
            factionsContainer.innerHTML = '<span style="color:var(--text-dim);font-size:0.8em;">此处尚无势力记载</span>';
        }

        // Wait slightly for DOM to render, then smooth scroll to the details panel for convenience
        setTimeout(() => {
            panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        }, 50);
    }

    function switchTab(event, tabId) {
        const button = event.currentTarget;
        const panel = button.closest('.main-panel');
        if (!panel) return;
        panel.querySelectorAll('.tab-btn').forEach(btn => btn.classList.remove('active'));
        panel.querySelectorAll('.tab-content').forEach(p => p.style.display = 'none');
        const tabToShow = document.getElementById('tab-' + tabId);
        if (tabToShow) {
            tabToShow.style.display = 'block';
        }
        button.classList.add('active');
    }

    const fairyGuide = {
        element: document.getElementById('fairy-guide'),
        textElement: document.getElementById('fairy-text'),
        toggleAndShowMessage() {
            const bubble = this.element.querySelector('.fairy-bubble');
            const isVisible = bubble.style.opacity === '1';

            if (isVisible) {
                bubble.style.opacity = '0';
                bubble.style.transform = 'translateY(10px)';
                bubble.style.pointerEvents = 'none';
            } else {
                if (!globalXmlData) return;

                const getMessagesFromXML = (category) => {
                    let nodes = globalXmlData.querySelectorAll(`fairy_messages > ${category} > message`);
                    if (nodes.length === 0 && category !== 'generic') {
                        nodes = globalXmlData.querySelectorAll('fairy_messages > generic > message');
                    }
                    if (nodes.length === 0) {
                        return ["道友，此地天机混沌，竟无一言可示..."];
                    }
                    return Array.from(nodes).map(node => node.textContent.trim());
                };

                const get = (tag) => globalXmlData.querySelector(tag)?.textContent.trim() || '0';
                const stats = {
                    hp: parseFloat(get('hp_current')), hpMax: parseFloat(get('hp_max')) || 100,
                    san: parseFloat(get('san_current')), sanMax: parseFloat(get('san_max')) || 100,
                    mp: parseFloat(get('mp_current')), mpMax: parseFloat(get('mp_max')) || 100
                };

                let messageCategory;
                if (stats.hp / stats.hpMax < 0.3) messageCategory = 'lowHealth';
                else if (stats.san / stats.sanMax < 0.4) messageCategory = 'lowSanity';
                else if (stats.mp / stats.mpMax < 0.2) messageCategory = 'lowMana';
                else messageCategory = 'generic';

                const pool = getMessagesFromXML(messageCategory);
                this.textElement.textContent = pool[Math.floor(Math.random() * pool.length)];
                bubble.style.opacity = '1';
                bubble.style.transform = 'translateY(0)';
                bubble.style.pointerEvents = 'auto';
            }
        },
        init() {
            const fairyAvatar = this.element.querySelector('.fairy-avatar');
            fairyAvatar.style.backgroundImage = `url('${fairyImages[currentFairyImageIndex]}')`;

            fairyAvatar.addEventListener('click', (e) => {
                if (e.button === 0) {
                    currentFairyImageIndex = (currentFairyImageIndex + 1) % fairyImages.length;
                    fairyAvatar.style.backgroundImage = `url('${fairyImages[currentFairyImageIndex]}')`;
                    this.toggleAndShowMessage();
                }
            });
        }
    };

    function handleReply(buttonElement, senderName) {
        if (!globalXmlData) {
            alert('数据未加载，无法回复。');
            return;
        }

        const sanCurrent = parseFloat(globalXmlData.querySelector('san_current')?.textContent.trim() || '0');

        if (sanCurrent < 20) {
            alert('神识不足20，无法传讯！');
            return;
        }

        const container = buttonElement.parentElement;
        const inputElement = container.querySelector('.reply-input');
        const replyText = inputElement.value.trim();

        if (!replyText) {
            alert('回复内容不能为空！');
            return;
        }

        const fullMessage = `传讯玉简回复 ${senderName}：「${replyText}」`;
        const isDirectSend = document.getElementById('direct-send-toggle')?.checked ?? true;

        if (typeof triggerSlash === 'function') {
            if (isDirectSend) {
                triggerSlash(`/send ${fullMessage} || /trigger`);
            } else {
                triggerSlash(`/setinput ${fullMessage}`);
            }
            inputElement.value = '';
            buttonElement.textContent = isDirectSend ? '已传讯' : '已复制功能生效';
            buttonElement.disabled = true;
            setTimeout(() => {
                buttonElement.textContent = '传讯';
                buttonElement.disabled = false;
            }, 2000);
        } else {
            console.error("无法找到 triggerSlash 函数，请确保在SillyTavern环境内运行。");
            alert("错误：无法连接到发送功能。");
        }
    }

    document.addEventListener('DOMContentLoaded', () => {
        const toggleWrapper = document.getElementById('toggle-label-wrapper');
        const toggleTooltip = document.getElementById('toggle-tooltip');
        let pressTimer;

        function startPress(e) {
            pressTimer = window.setTimeout(() => {
                toggleTooltip.classList.toggle('show');
            }, 500);
        }

        function cancelPress() {
            clearTimeout(pressTimer);
        }

        if (toggleWrapper && toggleTooltip) {
            toggleWrapper.addEventListener('touchstart', startPress, { passive: true });
            toggleWrapper.addEventListener('touchend', cancelPress);
            toggleWrapper.addEventListener('touchmove', cancelPress, { passive: true });
            toggleWrapper.addEventListener('mousedown', startPress);
            toggleWrapper.addEventListener('mouseup', cancelPress);
            toggleWrapper.addEventListener('mouseleave', cancelPress);
            toggleWrapper.addEventListener('contextmenu', (e) => {
                if (toggleTooltip.classList.contains('show')) {
                    e.preventDefault();
                }
            });
        }

        const dataSource = document.getElementById('data-source');
        fairyGuide.init();
        initMap();

        const fairyAvatar = document.querySelector('.fairy-avatar');
        const modalOverlay = document.getElementById('image-modal-overlay');
        const modalImage = document.getElementById('modal-image');
        const closeModal = document.querySelector('.image-modal-close');

        const factionOverlay = document.getElementById('faction-modal-overlay');
        const closeFaction = document.querySelector('.faction-modal-close');

        if (fairyAvatar) {
            fairyAvatar.addEventListener('contextmenu', function(e) {
                e.preventDefault();
                const style = window.getComputedStyle(fairyAvatar);
                const bgImage = style.backgroundImage;
                const imageUrl = bgImage.slice(5, -2);
                if (imageUrl) {
                    modalImage.src = imageUrl;
                    modalOverlay.style.display = 'flex';
                }
            });
        }

        if (closeModal) {
            closeModal.onclick = function() {
                modalOverlay.style.display = "none";
            }
        }

        if (modalOverlay) {
            modalOverlay.onclick = function(e) {
                if (e.target === modalOverlay) {
                    modalOverlay.style.display = "none";
                }
            }
        }

        if (closeFaction) {
            closeFaction.onclick = function() {
                factionOverlay.style.display = "none";
            }
        }
        if (factionOverlay) {
            factionOverlay.onclick = function(e) {
                if (e.target === factionOverlay) {
                    factionOverlay.style.display = "none";
                }
            }
        }

        if (dataSource && dataSource.value.trim()) {
            const parser = new DOMParser();
            globalXmlData = parser.parseFromString(dataSource.value, "text/html");

            // --- 新增防拦截逻辑开始：暂时冻结XML数据里的图片src属性 ---
            const xmlImages = globalXmlData.querySelectorAll('img');
            xmlImages.forEach(img => {
                if (img.hasAttribute('src')) {
                    img.setAttribute('data-seq-src', img.getAttribute('src'));
                    img.removeAttribute('src'); // 移除src阻止随后的DOM替换发起并发获取
                }
            });
            // --- 提取完成 ---

            renderUI(globalXmlData);

            // --- 新增防拦截逻辑开始：启动串行延迟加载队列 ---
            let seqImages = document.querySelectorAll('img[data-seq-src]');
            let seqIndex = 0;
            function loadSequential() {
                if (seqIndex >= seqImages.length) return;
                // 简单校验元素是否依然存在于页面
                if(seqImages[seqIndex]) {
                    seqImages[seqIndex].src = seqImages[seqIndex].getAttribute('data-seq-src');
                    seqImages[seqIndex].removeAttribute('data-seq-src');
                }
                seqIndex++;
                setTimeout(loadSequential, 800); // 设置每张图片间隔加载时间800毫秒
            }
            if(seqImages.length > 0) {
                setTimeout(loadSequential, 200); // 预留基础渲染时间后开始加载
            }
            // --- 队列部署完成 ---
        }

        const firstTab = document.querySelector('.tab-btn');
        if (firstTab) {
            firstTab.click();
        }
    });

