        .faction-modal-footer { font-size: 0.75em; color: var(--rare-text); opacity: 0.8; letter-spacing: 4px; margin-top: 10px; }

        .luck-modal-overlay { display: none; position: fixed; z-index: 99999; left: 0; top: 0; width: 100%; height: 100%; background-color: rgba(0,0,0,0.7); backdrop-filter: blur(4px); justify-content: center; align-items: center; }
        .luck-modal-content { background: linear-gradient(145deg, rgba(25, 20, 30, 0.95), rgba(15, 10, 15, 0.98)); border: 1px solid var(--border-metal); border-top: 2px solid var(--accent-gold); border-bottom: 2px solid var(--accent-gold); border-radius: 8px; width: 90%; max-width: 400px; max-height: 85vh; min-height: 400px; padding: 25px; box-shadow: 0 0 40px rgba(0,0,0,0.9), inset 0 0 20px rgba(255, 215, 0, 0.05); position: relative; animation: faction-pop 0.4s cubic-bezier(0.2, 0.8, 0.2, 1.1); display: flex; flex-direction: column; }
        .luck-modal-close { position: absolute; top: 8px; right: 15px; color: var(--text-dim); font-size: 28px; cursor: pointer; transition: 0.3s; line-height: 1; z-index: 10; }
        .luck-modal-close:hover { color: var(--accent-blood); transform: scale(1.1) rotate(90deg); }
        .luck-modal-header { font-size: 1.3em; font-weight: bold; color: var(--accent-gold); margin-bottom: 15px; padding-bottom: 12px; border-bottom: 1px dashed rgba(255, 255, 255, 0.1); text-shadow: 0 0 8px var(--accent-gold-glow); letter-spacing: 2px; text-align: center; flex-shrink: 0; }
        .luck-modal-body { overflow-y: auto; padding-right: 5px; flex: 1 1 auto; }
        .luck-modal-body::-webkit-scrollbar { width: 4px; }
        .luck-modal-body::-webkit-scrollbar-track { background: rgba(0,0,0,0.2); }
        .luck-modal-body::-webkit-scrollbar-thumb { background: var(--accent-gold); border-radius: 2px; }
        .luck-stat-row { cursor: pointer; transition: all 0.2s; border-radius: 4px; padding: 2px 4px; margin: 0 -4px; }
        .luck-stat-row:hover { background: rgba(255, 215, 0, 0.1); box-shadow: 0 0 8px rgba(255, 215, 0, 0.2); transform: translateX(2px); }

        .card-discard {
            position: absolute;
            top: 6px;
            right: 6px;
            width: 28px;
            height: 28px;
            border: 1px solid rgba(239,68,68,0.25);
            border-radius: 4px;
            background: rgba(239,68,68,0.08);
            color: rgba(239,68,68,0.6);
            font-size: 16px;
            line-height: 1;
            text-align: center;
            cursor: pointer;
            opacity: 0;
            transition: opacity 0.2s, background 0.2s, color 0.2s, border-color 0.2s;
            z-index: 2;
            padding: 0;
            font-family: 'JetBrains Mono', monospace;
        }
        .info-card:hover .card-discard,
        .partner-card:hover .card-discard,
        .npc-card:hover .card-discard,
        .skill-card:hover .card-discard,
        .quest-item:hover .card-discard,
        .inventory-item:hover .card-discard,
        .artifact-item:hover .card-discard,
        .luck-item:hover .card-discard { opacity: 1; }
        .card-discard:hover {
            background: rgba(239,68,68,0.25);
            border-color: rgba(239,68,68,0.6);
            color: #ff4d4d;
        }
        .info-card.discard-confirm .card-discard,
        .partner-card.discard-confirm .card-discard,
        .npc-card.discard-confirm .card-discard,
        .skill-card.discard-confirm .card-discard,
        .quest-item.discard-confirm .card-discard,
        .inventory-item.discard-confirm .card-discard,
        .artifact-item.discard-confirm .card-discard,
        .luck-item.discard-confirm .card-discard {
            opacity: 1;
            width: auto;
            padding: 0 8px;
            font-size: 12px;
            border-color: #ff4d4d;
            background: rgba(239,68,68,0.2);
            color: #ff4d4d;
        }
        .info-card.discard-confirm,
        .partner-card.discard-confirm,
        .npc-card.discard-confirm,
        .skill-card.discard-confirm,
        .quest-item.discard-confirm,
        .inventory-item.discard-confirm,
        .artifact-item.discard-confirm,
        .luck-item.discard-confirm {
            border-color: rgba(239,68,68,0.4) !important;
        }
        .info-card.discarding,
        .partner-card.discarding,
        .npc-card.discarding,
        .skill-card.discarding,
        .quest-item.discarding,
        .inventory-item.discarding,
        .wx-list-item.discarding,
        .artifact-item.discarding,
        .luck-item.discarding {
            animation: discard-fade 0.35s ease forwards;
        }
        @keyframes discard-fade {
            0% { opacity: 1; transform: scale(1); }
            100% { opacity: 0; transform: scale(0.85) translateY(8px); }
        }

        #tab-messages { display: none; flex-direction: column; height: 480px; padding: 10px; box-sizing: border-box; overflow: hidden; }

        .wx-list-view { display: flex; flex-direction: column; gap: 10px; overflow-y: auto; flex-grow: 1; padding-right: 5px; scrollbar-width: thin; scrollbar-color: var(--border-metal) rgba(0,0,0,0.3); }
        .wx-list-item { display: flex; align-items: center; padding: 10px; background: rgba(30,30,35,0.6); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; cursor: pointer; transition: background 0.2s, transform 0.2s; position: relative; overflow: hidden; flex-shrink: 0; user-select: none; }
        .wx-list-item:hover { background: rgba(40,40,45,0.8); transform: translateY(-1px); }
        .wx-avatar-container { width: 50px; height: 50px; border-radius: 6px; overflow: hidden; margin-right: 15px; position: relative; flex-shrink: 0; border: 1px solid rgba(255,255,255,0.2); background: rgba(0,0,0,0.5); }
        .wx-avatar-container img { width: 100%; height: 100%; object-fit: cover; cursor: zoom-in; }
        .wx-avatar-custom-btn { position: absolute; bottom: 0; left: 0; width: 100%; background: rgba(0,0,0,0.6); color: #fff; text-align: center; font-size: 10px; padding: 2px 0; cursor: pointer; opacity: 0; transition: opacity 0.2s; }
        .wx-avatar-container:hover .wx-avatar-custom-btn { opacity: 1; }
        .wx-unread-dot { position: absolute; top: -2px; right: -2px; width: 12px; height: 12px; background-color: var(--accent-blood); border-radius: 50%; box-shadow: 0 0 5px var(--accent-blood-glow); display: none; z-index: 5; border: 1px solid #000; }
        .wx-unread-dot.show { display: block; }
        .wx-list-info { flex-grow: 1; overflow: hidden; }
        .wx-list-name { font-size: 1.1em; color: var(--accent-gold); font-weight: bold; margin-bottom: 5px; }
        .wx-list-preview { font-size: 0.85em; color: var(--text-dim); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

        .wx-chat-view { display: none; flex-direction: column; height: 100%; position: relative; border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; overflow: hidden; }
        .wx-chat-bg { position: absolute; top: 0; left: 0; width: 100%; height: 100%; background-size: cover; background-position: center; filter: brightness(0.35); z-index: 0; }
        .wx-chat-header { position: relative; z-index: 10; display: flex; align-items: center; padding: 12px 15px; background: linear-gradient(to bottom, rgba(10,10,15,0.9), rgba(10,10,15,0.7)); border-bottom: 1px solid rgba(255,255,255,0.1); }
        .wx-back-btn { cursor: pointer; color: var(--text-dim); font-size: 1.1em; margin-right: 15px; transition: color 0.2s; font-weight: bold; }
        .wx-back-btn:hover { color: var(--accent-gold); }
        .wx-chat-title { font-size: 1.15em; color: var(--text-main); font-weight: bold; cursor: pointer; flex-grow: 1; text-align: center; margin-right: 10px; transition: color 0.2s; text-shadow: 0 1px 2px #000; }
        .wx-chat-title:hover { color: var(--accent-mana); }
        .wx-api-btn { cursor: pointer; color: var(--text-dim); font-size: 1.2em; transition: color 0.2s, transform 0.2s; }
        .wx-api-btn:hover { color: var(--accent-mana); transform: rotate(90deg); }

        .wx-chat-messages { position: relative; z-index: 1; flex-grow: 1; padding: 15px; overflow-y: auto; display: flex; flex-direction: column; gap: 15px; scrollbar-width: thin; min-height: 0; }
        .wx-msg-row { display: flex; flex-direction: column; max-width: 85%; }
        .wx-msg-left { align-self: flex-start; }
        .wx-msg-right { align-self: flex-end; align-items: flex-end; }
        .wx-msg-sender { font-size: 0.75em; color: rgba(255,255,255,0.6); margin-bottom: 4px; padding: 0 5px; text-shadow: 0 1px 1px #000; }
        .wx-msg-bubble { padding: 10px 14px; border-radius: 8px; font-size: 0.9em; line-height: 1.5; word-wrap: break-word; box-shadow: 0 2px 6px rgba(0,0,0,0.4); backdrop-filter: blur(2px); white-space: pre-wrap; }
        .wx-msg-left .wx-msg-bubble { background: rgba(30, 40, 50, 0.85); border: 1px solid rgba(77, 166, 255, 0.3); color: #e0f0ff; border-top-left-radius: 0; }
        .wx-msg-right .wx-msg-bubble { background: rgba(46, 204, 113, 0.25); border: 1px solid rgba(46, 204, 113, 0.4); color: #e0f0ff; border-top-right-radius: 0; }

        .wx-msg-actions { display: none; gap: 10px; margin-top: 4px; font-size: 0.75em; opacity: 0.8; justify-content: flex-end; }
        .wx-msg-left .wx-msg-actions { justify-content: flex-start; }
        .wx-msg-row:hover .wx-msg-actions { display: flex; }
        .wx-msg-action-btn { cursor: pointer; color: var(--text-dim); transition: color 0.2s; background: rgba(0,0,0,0.3); padding: 2px 6px; border-radius: 4px; border: 1px solid rgba(255,255,255,0.1); }
        .wx-msg-action-btn:hover { color: var(--accent-gold); border-color: var(--accent-gold); background: rgba(255,215,0,0.1); }

        .wx-chat-input-area { position: relative; z-index: 105; padding: 12px; background: rgba(10,10,15,0.9); border-top: 1px solid rgba(255,255,255,0.1); flex-shrink: 0; }

        .wx-detail-modal { display: none; position: absolute; top: 45px; left: 50%; transform: translateX(-50%); background: linear-gradient(145deg, rgba(25,25,30,0.95), rgba(15,15,20,0.98)); border: 1px solid var(--accent-mana); border-radius: 8px; padding: 15px; z-index: 100; box-shadow: 0 5px 20px rgba(0,0,0,0.6), inset 0 0 10px rgba(77,166,255,0.1); width: 200px; text-align: center; backdrop-filter: blur(5px); animation: fadeIn 0.2s ease; }
        .wx-detail-modal.show { display: block; }
        .wx-detail-item { margin: 10px 0; font-size: 0.95em; display: flex; justify-content: space-between; border-bottom: 1px dashed rgba(255,255,255,0.1); padding-bottom: 6px; }
        .wx-detail-item:last-child { border-bottom: none; margin-bottom: 0; }

        @media (max-width: 700px) {
            .terminal-container { border-radius: 0; border: none; border-top: 2px solid var(--border-metal); border-bottom: 2px solid var(--border-metal); }
            .content-grid { grid-template-columns: 1fr; }
            .status-panel { flex-direction: row; padding: 15px; gap: 20px; flex-wrap: wrap; justify-content: center; background-color: rgba(20, 18, 22, 0.8); border-right: none; border-bottom: 1px solid rgba(255,255,255,0.1); }
            .avatar-frame { width: 70px; height: 70px; }
            .stat-group { flex: 1; min-width: 200px; }
            .rank-tag { margin-top: -5px; }
            .tab-content { max-height: 350px; padding: 15px; }
            #tab-messages { padding: 10px; height: 350px; }
            .wx-chat-input-area { padding: 8px; }
            .message-reply-container { gap: 6px; }
            .reply-button { min-width: 80px; padding: 8px 12px; }
            .fairy-container { right: 10px; bottom: 10px; }
            .fairy-bubble { max-width: 180px; font-size: 0.85em; padding: 10px; }
            .wx-msg-actions { display: flex; flex-wrap: wrap; }
        }

        .portrait-custom-btn { display: inline-block; width: auto; margin-left: 8px; background: linear-gradient(to right, transparent, rgba(100, 180, 255, 0.1), transparent); border: 1px dashed rgba(100, 180, 255, 0.4); color: #64b4ff; padding: 6px 12px; text-align: center; border-radius: 4px; cursor: pointer; font-size: 0.8em; transition: all 0.3s; letter-spacing: 1px; }
        .portrait-custom-btn:hover { background: linear-gradient(to right, transparent, rgba(100, 180, 255, 0.2), box-shadow: 0 0 8px rgba(100, 180, 255, 0.3); }
        .portrait-file-label { display: flex; align-items: center; justify-content: center; padding: 8px 16px; background: linear-gradient(135deg, rgba(100,180,255,0.2), rgba(100,180,255,0.1)); border: 1px dashed rgba(100,180,255,0.5); border-radius: 6px; color: #64b4ff; cursor: pointer; font-size: 0.85em; white-space: nowrap; transition: all 0.3s; }
        .portrait-file-label:hover { background: linear-gradient(135deg, rgba(100,180,255,0.3), rgba(100,180,255,0.15)); }
        .portrait-custom-modal, .api-config-modal { display: none; position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.7); z-index: 9999; justify-content: center; align-items: center; }
        .portrait-custom-modal.show, .api-config-modal.show { display: flex; }
        .portrait-custom-dialog, .api-config-dialog { background: linear-gradient(145deg, rgba(20,25,35,0.95), rgba(10,15,25,0.98)); border: 1px solid rgba(100, 180, 255, 0.4); border-radius: 12px; padding: 25px; max-width: 500px; width: 90%; box-shadow: 0 0 30px rgba(100, 180, 255, 0.3); }
        .portrait-custom-dialog h3, .api-config-dialog h3 { color: #64b4ff; margin: 0 0 15px 0; text-align: center; font-size: 1.1em; letter-spacing: 2px; }
        .portrait-custom-dialog label, .api-config-dialog label { color: #a0b8cc; font-size: 0.9em; display: block; margin-bottom: 5px; }
        .portrait-custom-dialog input, .api-config-dialog input, .api-config-dialog select, .api-config-dialog textarea { width: 100%; padding: 10px; border: 1px solid rgba(100, 180, 255, 0.3); border-radius: 6px; background: rgba(0,0,0,0.4); color: #e0f0ff; font-size: 0.9em; margin-bottom: 12px; box-sizing: border-box; font-family: inherit; }
        .portrait-custom-dialog input:focus, .api-config-dialog input:focus, .api-config-dialog select:focus, .api-config-dialog textarea:focus { outline: none; border-color: #64b4ff; box-shadow: 0 0 10px rgba(100, 180, 255, 0.2); }
        .portrait-custom-dialog .btn-row, .api-config-dialog .btn-row { display: flex; gap: 10px; justify-content: center; margin-top: 5px; }
        .portrait-custom-dialog .btn-confirm, .api-config-dialog .btn-confirm { background: linear-gradient(135deg, #1a5fa8, #2a7fd8); color: #fff; border: none; padding: 8px 24px; border-radius: 6px; cursor: pointer; font-size: 0.9em; letter-spacing: 1px; transition: all 0.3s; }
        .portrait-custom-dialog .btn-confirm:hover, .api-config-dialog .btn-confirm:hover { background: linear-gradient(135deg, #2a7fd8, #3a8fe8); box-shadow: 0 0 12px rgba(100, 180, 255, 0.4); }
        .portrait-custom-dialog .btn-cancel, .api-config-dialog .btn-cancel { background: rgba(255,255,255,0.1); color: #a0b8cc; border: 1px solid rgba(255,255,255,0.2); padding: 8px 24px; border-radius: 6px; cursor: pointer; font-size: 0.9em; transition: all 0.3s; }
        .portrait-custom-dialog .btn-cancel:hover, .api-config-dialog .btn-cancel:hover { background: rgba(255,255,255,0.2); }
        .portrait-custom-dialog .btn-reset { background: rgba(255,80,80,0.15); color: #ff6b6b; border: 1px solid rgba(255,80,80,0.3); padding: 8px 24px; border-radius: 6px; cursor: pointer; font-size: 0.9em; transition: all 0.3s; }
        .portrait-custom-dialog .btn-reset:hover { background: rgba(255,80,80,0.25); }
        .portrait-preview { width: 100%; max-height: 120px; object-fit: contain; border-radius: 6px; border: 1px solid rgba(255,255,255,0.1); margin-bottom: 10px; display: none; }
        .portrait-preview.show { display: block; }
        .portrait-custom-hint { font-size: 0.75em; color: #6a8a9a; margin-bottom: 10px; text-align: center; }
    </style>
</head>
<body>
<!-- disable-default-loading -->
<div class="terminal-container">
    <div class="top-bar"></div>
    <div class="header">
        <div class="guild-badge">
            <!-- 移除了内联 onclick，改在底部JS中绑定 -->
            <div class="guild-logo" id="hero-info-btn" title="点击查看主角信息">修</div>
            <div class="guild-name">面板</div>
        </div>
        <div class="time-display" id="env-status"></div>

        <!-- 下拉的主角信息面板 -->
        <div class="hero-info-dropdown" id="hero-info-dropdown">
            <div class="stat-row"><div class="stat-label"><span>姓名</span><span id="name-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
            <div class="stat-row"><div class="stat-label"><span>性别</span><span id="gender-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
            <div class="stat-row"><div class="stat-label"><span>容貌</span><span id="appearance-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
            <div class="stat-row"><div class="stat-label"><span>身形</span><span id="body-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
            <div class="stat-row"><div class="stat-label"><span>衣着</span><span id="clothing-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
        </div>
    </div>
    <div class="content-grid">
        <div class="status-panel">
            <div class="avatar-wrapper">
                <div class="avatar-frame"><div class="user_avatar"></div></div>
                <div class="rank-tag"></div>
            </div>
            <div class="stat-group">
                <div class="stat-row"><div class="stat-label"><span>生命</span><span id="hp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-hp" id="hp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>精血</span><span id="blood-value"></span></div><div class="progress-bg"><div class="progress-fill fill-hp" id="blood-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>灵力</span><span id="mp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-mp" id="mp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>修为</span><span id="exp-value"></span></div><div class="progress-bg"><div class="progress-fill fill-exp" id="exp-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>神识</span><span id="san-value"></span></div><div class="progress-bg"><div class="progress-fill fill-san" id="san-bar"></div></div></div>
                <div class="stat-row"><div class="stat-label"><span>道心</span><span id="daoxin-value"></span></div><div class="progress-bg"><div class="progress-fill fill-daoxin" id="daoxin-bar"></div></div></div>

                <div class="stat-row"><div class="stat-label"><span>神念</span><span id="san-status" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
                <div class="stat-row luck-stat-row" onclick="document.getElementById('luck-modal-overlay').style.display='flex'">
                    <div class="stat-label">
                        <span title="点击查看气运详情">气运</span>
                        <span id="luck-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span>
                    </div>
                </div>
                <div class="stat-row"><div class="stat-label"><span>灵根</span><span id="spirit-root-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;"></span></div></div>
                <div class="stat-row luck-stat-row" id="clan-row">
                    <div class="stat-label">
                        <span title="点击查看宗门详情">宗门</span>
                        <span id="clan-value" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;">无</span>
                    </div>
                </div>
                <div class="stat-row"><div class="stat-label"><span>状态</span><span id="status-effects" class="rare-text" style="font-weight:normal; text-align:right; flex:1; margin-left:10px; word-break:break-all;">无</span></div></div>
            </div>
        </div>
        <div class="main-panel">
            <div class="nav-tabs">
                <button class="tab-btn active" onclick="switchTab(event, 'dashboard')">概览</button>
                <button class="tab-btn" onclick="switchTab(event, 'skills')">功法</button>
                <button class="tab-btn" onclick="switchTab(event, 'partners')">道侣</button>
                <button class="tab-btn" onclick="switchTab(event, 'npcs')">人物</button>
                <button class="tab-btn" onclick="switchTab(event, 'pets')">灵宠</button>
                <button class="tab-btn" onclick="switchTab(event, 'quests')">机遇</button>
                <button class="tab-btn" onclick="switchTab(event, 'database')">绝色榜</button>
                <button class="tab-btn" onclick="switchTab(event, 'world_events')">动向</button>
                <button class="tab-btn" onclick="switchTab(event, 'messages')">玉简</button>
                <button class="tab-btn" onclick="switchTab(event, 'map')">舆图</button>
            </div>

            <!-- Other Tabs Content -->
            <div id="tab-dashboard" class="tab-content" style="display: block;"></div>
            <div id="tab-skills" class="tab-content" style="display: none;"></div>
            <div id="tab-partners" class="tab-content" style="display: none;"></div>
            <div id="tab-npcs" class="tab-content" style="display: none;"></div>
            <div id="tab-pets" class="tab-content" style="display: none;"></div>
            <div id="tab-quests" class="tab-content" style="display: none;"></div>
            <div id="tab-database" class="tab-content" style="display: none;"></div>
            <div id="tab-world_events" class="tab-content" style="display: none;"></div>

            <!-- 玉简 Tab Content -->
            <div id="tab-messages" class="tab-content">
