    /* 获取立绘URL：角色自身性别为女性且有姓转版时优先使用 */
    function getPortraitUrl(name, gender) {
        if (charPortraitsFemale[name] && gender && /^女/.test(gender)) {
            return charPortraitsFemale[name];
        }
        return charPortraits[name];
    }

    /* 从 localStorage 加载自定义立绘并合并 */
    (function() {
        try {
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                const customPortraits = JSON.parse(saved);
                Object.assign(charPortraits, customPortraits);
            }
        } catch(e) {
            console.warn('[道渊] 加载自定义立绘失败:', e);
        }
    })();

    /* 保存自定义立绘到 localStorage */
    window.saveCustomPortrait = function(name, url) {
        try {
            let customPortraits = {};
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                customPortraits = JSON.parse(saved);
            }
            customPortraits[name] = url;
            const dataStr = JSON.stringify(customPortraits);
            if (url && url.startsWith('data:') && url.length > 2 * 1024 * 1024) {
                console.warn('[道渊] 单张立绘过大(' + (url.length/1024/1024).toFixed(1) + 'MB)，建议压缩图片或使用图床');
            }
            if (dataStr.length > 3 * 1024 * 1024) {
                alert('⚠️ 立绘数据过大（' + (dataStr.length/1024/1024).toFixed(1) + 'MB），已接近localStorage上限(5MB)。建议使用图床URL而非本地图片，或删除部分自定义立绘。');
            }
            if (dataStr.length > 4.5 * 1024 * 1024) {
                alert('⚠️ 立绘数据超过4.5MB，localStorage可能无法保存！请立即使用图床URL替代本地图片。');
                return false;
            }
            localStorage.setItem('daoyuan_custom_portraits', dataStr);
            charPortraits[name] = url;
            if (typeof populateCharacterData === 'function') {
                populateCharacterData();
            }
            return true;
        } catch(e) {
            console.warn('[道渊] 保存自定义立绘失败:', e);
            if (e.name === 'QuotaExceededError') {
                alert('⚠️ 存储空间不足！本地图片过多，请使用图床URL（如 catbox.moe）替代，或删除一些不需要的自定义立绘。');
            } else {
                alert('保存失败：' + e.message);
            }
            return false;
        }
    };

    /* 处理本地图片上传 */
    window.handlePortraitFileUpload = function(fileInput, charName) {
        const file = fileInput.files[0];
        if (!file) return;
        if (file.size > 5 * 1024 * 1024) {
            alert('图片文件过大，请选择小于5MB的图片（建议使用图床URL）');
            return;
        }
        if (!file.type.startsWith('image/')) {
            alert('请选择有效的图片文件');
            return;
        }
        const fileNameSpan = document.getElementById('portrait-file-name');
        if (fileNameSpan) {
            fileNameSpan.textContent = '📷 ' + file.name + ' (' + (file.size/1024).toFixed(1) + 'KB)';
            fileNameSpan.style.color = '#64ff8a';
        }
        const reader = new FileReader();
        reader.onload = function(e) {
            const base64 = e.target.result;
            const previewImg = document.getElementById('portrait-preview-img');
            if (previewImg) {
                previewImg.src = base64;
                previewImg.classList.add('show');
                previewImg.onerror = null;
            }
            const urlInput = document.getElementById('portrait-url-input');
            if (urlInput) {
                urlInput.value = base64;
            }
        };
        reader.readAsDataURL(file);
    };

    /* 删除自定义立绘（恢复默认） */
    window.removeCustomPortrait = function(name) {
        try {
            let customPortraits = {};
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                customPortraits = JSON.parse(saved);
            }
            delete customPortraits[name];
            localStorage.setItem('daoyuan_custom_portraits', JSON.stringify(customPortraits));
            if (typeof populateCharacterData === 'function') {
                populateCharacterData();
            }
            return true;
        } catch(e) {
            console.warn('[道渊] 删除自定义立绘失败:', e);
            return false;
        }
    };

    /* 打开自定义立绘弹窗 */
    window.openCustomPortraitDialog = function(charName) {
        const existing = document.getElementById('portrait-custom-modal');
        if (existing) existing.remove();

        const currentUrl = charPortraits[charName] || '';
        const isCustom = (function() {
            try {
                const saved = localStorage.getItem('daoyuan_custom_portraits');
                if (saved) {
                    const cp = JSON.parse(saved);
                    return cp.hasOwnProperty(charName);
                }
            } catch(e) {}
            return false;
        })();

        const modal = document.createElement('div');
        modal.id = 'portrait-custom-modal';
        modal.className = 'portrait-custom-modal show';
        modal.innerHTML = `
            <div class="portrait-custom-dialog">
                <h3>🎨 自定义立绘 - ${charName}</h3>
                <img class="portrait-preview" id="portrait-preview-img" alt="预览" style="display:none;" onerror="this.style.display='none'">
                <div style="display:flex;gap:8px;align-items:stretch;margin-bottom:12px;">
                    <label for="portrait-file-input" class="portrait-file-label">📁 选择本地图片</label>
                    <input type="file" id="portrait-file-input" accept="image/*" style="display:none;" onchange="window.handlePortraitFileUpload(this, '${charName}')">
                    <span id="portrait-file-name" style="flex:1;display:flex;align-items:center;color:var(--text-dim);font-size:0.8em;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">或输入URL地址</span>
                </div>
                <label>图片URL地址</label>
                <input type="text" id="portrait-url-input" placeholder="请输入立绘图片的URL地址（支持常见图床）" value="${currentUrl}">
                <div class="portrait-custom-hint">💡 支持上传本地图片（自动保存），或粘贴图床链接（catbox.moe、postimg.cc等）</div>
                <div class="btn-row">
                    <button class="btn-confirm" id="portrait-confirm-btn">✅ 确认保存</button>
                    ${isCustom ? '<button class="btn-reset" id="portrait-reset-btn">🔄 恢复默认</button>' : ''}
                    <button class="btn-cancel" id="portrait-cancel-btn">取消</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

        const previewImgEl = modal.querySelector('#portrait-preview-img');
        if (currentUrl) {
            previewImgEl.src = currentUrl;
            previewImgEl.classList.add('show');
            previewImgEl.style.display = '';
        }

        const urlInput = modal.querySelector('#portrait-url-input');
        const previewImg = modal.querySelector('#portrait-preview-img');
        urlInput.addEventListener('input', function() {
            const val = this.value.trim();
            if (val) {
                previewImg.src = val;
                previewImg.classList.add('show');
            } else {
                previewImg.classList.remove('show');
            }
        });

        modal.querySelector('#portrait-confirm-btn').addEventListener('click', function() {
            const url = urlInput.value.trim();
            if (!url) {
                alert('请输入有效的图片URL地址');
                return;
            }
            if (window.saveCustomPortrait(charName, url)) {
                const prevImg = modal.querySelector('#portrait-preview-img');
                if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                modal.remove();
            } else {
                alert('保存失败，请重试');
            }
        });

        modal.querySelector('#portrait-cancel-btn').addEventListener('click', function() {
            const prevImg = modal.querySelector('#portrait-preview-img');
            if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
            modal.remove();
        });

        const resetBtn = modal.querySelector('#portrait-reset-btn');
        if (resetBtn) {
            resetBtn.addEventListener('click', function() {
                if (confirm('确定要恢复「' + charName + '」的默认立绘吗？')) {
                    window.removeCustomPortrait(charName);
                    const prevImg = modal.querySelector('#portrait-preview-img');
                    if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                    modal.remove();
                    if (confirm('需要刷新页面以完全恢复默认立绘，是否刷新？')) {
                        location.reload();
                    }
                }
            });
        }

        modal.addEventListener('click', function(e) {
            if (e.target === modal) {
                const prevImg = modal.querySelector('#portrait-preview-img');
                if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                modal.remove();
            }
        });

        setTimeout(() => urlInput.focus(), 100);
    };

    window.appendChatMessage = async function(charName, sender, content) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) {
                console.warn('找不到消息历史');
                return;
            }
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data && fullData.stat_data.玉简) {
                    if (!fullData.stat_data.玉简[charName]) {
                        fullData.stat_data.玉简[charName] = { 历史记录: {} };
                    }
                    const history = fullData.stat_data.玉简[charName].历史记录 || {};
                    const newMsgId = 'msg_' + Date.now() + Math.floor(Math.random() * 1000);
                    const now = new Date();
                    const timeStr = now.getHours().toString().padStart(2, '0') + ':' + now.getMinutes().toString().padStart(2, '0');

                    history[newMsgId] = {
                        "发送者": sender,
                        "内容": content,
                        "时间": timeStr
                    };

                    fullData.stat_data.玉简[charName].历史记录 = history;
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });
                    if(typeof populateCharacterData === 'function') populateCharacterData();
                }
            } else {
                 console.warn('MVU 未初始化');
            }
        } catch (err) {
            console.error('[道渊状态栏] 更新玉简消息失败:', err);
        }
    };

