    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const startScreen = document.getElementById('start-screen');
            const creationScreen = document.getElementById('character-creation-screen');
            const startButton = document.getElementById('start-button');
            const initialWarning = document.getElementById('initial-warning');
            const modeSelection = document.getElementById('mode-selection');
            const simpleModeBtn = document.getElementById('simple-mode-btn');
            const normalModeBtn = document.getElementById('normal-mode-btn');
            const hardModeBtn = document.getElementById('hard-mode-btn');

            const confirmButton = document.getElementById('confirm-creation-button');
            const drawFortuneBtn = document.getElementById('draw-fortune-btn');
            const cheatToggleSection = document.getElementById('cheat-toggle-section');
            const cheatToggle = document.getElementById('cheat-toggle-checkbox');
            const eroToggle = document.getElementById('ero-toggle-checkbox');
            const heavyToggle = document.getElementById('heavy-toggle-checkbox');
            const browseAllBtn = document.getElementById('browse-all-fortunes-btn');
            const customFortuneToggle = document.getElementById('custom-fortune-toggle');
            const customFortuneDivider = document.getElementById('custom-fortune-divider');
            const customSelectPanel = document.getElementById('custom-select-panel');
            const authOverlay = document.getElementById('custom-fortune-auth-overlay');
            const authInput = document.getElementById('custom-fortune-answer');
            const authConfirmBtn = document.getElementById('auth-confirm-btn');
            const authCancelBtn = document.getElementById('auth-cancel-btn');
            const authVerifyBody = document.getElementById('auth-verify-body');
            const authMsgBody = document.getElementById('auth-msg-body');
            const authMsgTitle = document.getElementById('auth-msg-title');
            const authMsgText = document.getElementById('auth-msg-text');
            const authMsgOkBtn = document.getElementById('auth-msg-ok-btn');

            // 告道渊同胞书弹窗
            const daoyuanLetterOverlay = document.getElementById('daoyuan-letter-overlay');
            const daoyuanLetterConfirm = document.getElementById('daoyuan-letter-confirm');
            const daoyuanLetterHint = document.getElementById('daoyuan-letter-hint');
            const daoyuanLetterBody = daoyuanLetterOverlay.querySelector('.daoyuan-letter-body');

            const entryTooltip = document.createElement('div');
            entryTooltip.className = 'entry-tooltip';
            document.body.appendChild(entryTooltip);

            function showEntryTooltip(text, target) {
                entryTooltip.textContent = text;
                const rect = target.getBoundingClientRect();
                let left = rect.left;
                let top = rect.bottom + 4;
                const tw = Math.min(280, window.innerWidth - 20);
                if (left + tw > window.innerWidth - 10) left = window.innerWidth - tw - 10;
                if (left < 10) left = 10;
                if (top + 80 > window.innerHeight) top = rect.top - 80;
                entryTooltip.style.left = left + 'px';
                entryTooltip.style.top = top + 'px';
                entryTooltip.style.maxWidth = tw + 'px';
                entryTooltip.classList.add('visible');
            }
            function hideEntryTooltip() {
                entryTooltip.classList.remove('visible');
            }

            const customTrueSection = document.getElementById('custom-true-section');
            const customTrueGrid = document.getElementById('custom-true-grid');
            const customNormalSection = document.getElementById('custom-normal-section');
            const customNormalGrid = document.getElementById('custom-normal-grid');
            const customEroGrid = document.getElementById('custom-ero-grid');
            const customEroSection = document.getElementById('custom-ero-section');
            const customHeavySection = document.getElementById('custom-heavy-section');
            const customHeavyGrid = document.getElementById('custom-heavy-grid');
            const selectedFortuneTags = document.getElementById('selected-fortune-tags');
            const fortuneTagsScroll = selectedFortuneTags.querySelector('.fortune-tags-scroll');

            const nameInput = document.getElementById('char-name');
            const genderInput = document.getElementById('char-gender');
            const raceInput = document.getElementById('char-race');
            const appearanceInput = document.getElementById('char-appearance');
            const realmInput = document.getElementById('char-realm');
            const realmSelect = document.getElementById('char-realm-select');
            const identityInput = document.getElementById('char-identity');

            const spiritRootTextarea = document.getElementById('char-spirit-root');
            const techniqueTextarea = document.getElementById('char-technique');

            const hardModeSpiritRootSection = document.getElementById('hard-mode-spirit-root-section');
            const spiritRootResult = document.getElementById('spirit-root-result');
            const rollSpiritRootBtn = document.getElementById('roll-spirit-root-btn');

            // 音乐和返回按钮控制
            const bgm = document.getElementById('bgm');
            const musicToggle = document.getElementById('music-toggle');
            const backToModeBtn = document.getElementById('back-to-mode-btn');

            // 存档相关DOM
            const archiveNameInput = document.getElementById('archive-name');
            const archiveSelect = document.getElementById('archive-select');
            const btnSaveArchive = document.getElementById('btn-save-archive');
            const btnLoadArchive = document.getElementById('btn-load-archive');
            const btnDeleteArchive = document.getElementById('btn-delete-archive');
            const btnExportArchive = document.getElementById('btn-export-archive');
            const btnImportArchive = document.getElementById('btn-import-archive');
            const importFileInput = document.getElementById('import-file');

            // 存档折叠控制
            const archiveToggleTitle = document.getElementById('archive-toggle-title');
            const archiveContent = document.getElementById('archive-content');
            const archiveToggleIcon = document.getElementById('archive-toggle-icon');

            archiveToggleTitle.addEventListener('click', () => {
                if (archiveContent.style.display === 'none') {
                    archiveContent.style.display = 'block';
                    archiveToggleIcon.style.transform = 'rotate(180deg)';
                } else {
                    archiveContent.style.display = 'none';
                    archiveToggleIcon.style.transform = 'rotate(0deg)';
                }
            });

            let currentMode = 'normal';
            let spiritRootRollsLeft = 3;
            let fortuneRollsLeft = 3;
            let hardModeSpiritRootValue = "";

            // ===== MVU 初始化 =====
            let mvuReady = false;
            async function initMvu() {
                try {
                    if (typeof waitGlobalInitialized === 'function') {
                        await waitGlobalInitialized('Mvu');
                        if (typeof Mvu !== 'undefined' && typeof getCurrentMessageId === 'function') {
                            mvuReady = true;
                            console.log('[道渊创建] MVU连接成功');
                        }
                    }
                } catch (e) {
                    console.warn('[道渊创建] MVU初始化失败:', e);
                }
            }
            initMvu();

            // ===== MVU 字段级同步工具 =====
            async function syncToMvu(path, value) {
                if (!mvuReady) return;
                try {
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;
                    _.set(data, path, value);
                    await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                } catch (e) {
                    console.warn('[道渊创建] MVU同步失败:', path, e);
                }
            }
            function syncCompanion(field, value) {
                const name = companionNameInput.value.trim();
                if (!name) return;
                syncToMvu(`stat_data.道侣.${name}.${field}`, value);
            }
            async function initMvuDefaults() {
                if (!mvuReady) return;
                try {
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;
                    const defaults = {
                        'stat_data.世界': { 当前时间: '未知', 当前地点: '未知', 危机程度: '无', 动向: {} },
                        'stat_data.主角.境界': '凡人（DC:0）',
                        'stat_data.主角.生命': 100,
                        'stat_data.主角.精血': 100,
                        'stat_data.主角.灵力': 100,
                        'stat_data.主角.修为': 0,
                        'stat_data.主角.神识': 100,
                        'stat_data.主角.道心': 50,
                        'stat_data.主角.神念': '无',
                        'stat_data.主角.宗门': '无',
                        'stat_data.主角.所在界': '玄天界',
                        'stat_data.主角.灵根': '未知',
                        'stat_data.主角.气运': {},
                        'stat_data.主角.功法': {},
                        'stat_data.主角.炼丹': { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 },
                        'stat_data.主角.炼器': { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 },
                        'stat_data.主角.状态': '无异常',
                        'stat_data.主角.储物袋': {},
                        'stat_data.主角.器物': {},
                        'stat_data.道侣': {},
                        'stat_data.灵宠': {},
                        'stat_data.人物': {},
                        'stat_data.机遇': {},
                        'stat_data.绝色榜': {},
                        'stat_data.玉简': {}
                    };
                    let changed = false;
                    for (const [p, v] of Object.entries(defaults)) {
                        if (_.get(data, p) === undefined) {
                            _.set(data, p, v);
                            changed = true;
                        }
                    }
                    if (changed) await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                } catch (e) {}
            }
            setTimeout(initMvuDefaults, 800);

            // 强制重置MVU到默认状态（返回时调用，覆盖已有数据）
            async function resetMvuToDefaults() {
                if (!mvuReady) return;
                try {
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;
                    const defaults = {
                        'stat_data.世界': { 当前时间: '未知', 当前地点: '未知', 危机程度: '无', 动向: {} },
                        'stat_data.主角.境界': '凡人（DC:0）',
                        'stat_data.主角.生命': 100,
                        'stat_data.主角.精血': 100,
                        'stat_data.主角.灵力': 100,
                        'stat_data.主角.修为': 0,
                        'stat_data.主角.神识': 100,
                        'stat_data.主角.道心': 50,
                        'stat_data.主角.神念': '无',
                        'stat_data.主角.宗门': '无',
                        'stat_data.主角.所在界': '玄天界',
                        'stat_data.主角.灵根': '未知',
                        'stat_data.主角.气运': {},
                        'stat_data.主角.功法': {},
                        'stat_data.主角.炼丹': { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 },
                        'stat_data.主角.炼器': { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 },
                        'stat_data.主角.状态': '无异常',
                        'stat_data.主角.储物袋': {},
                        'stat_data.主角.器物': {},
                        'stat_data.道侣': {},
                        'stat_data.灵宠': {},
                        'stat_data.人物': {},
                        'stat_data.机遇': {},
                        'stat_data.绝色榜': {},
                        'stat_data.玉简': {}
                    };
                    for (const [p, v] of Object.entries(defaults)) {
                        _.set(data, p, v);
                    }
                    await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                } catch (e) {}
            }

            // 尝试自动播放并处理浏览器限制
            bgm.volume = 0.4;
            let playPromise = bgm.play();
            if (playPromise !== undefined) {
                playPromise.catch(error => {
                    document.body.addEventListener('click', function firstClick() {
                        if (!musicToggle.classList.contains('muted')) {
                            bgm.play();
                        }
                        document.body.removeEventListener('click', firstClick);
                    });
                });
            }

            musicToggle.addEventListener('click', (e) => {
                e.stopPropagation();
                if (bgm.paused) {
                    bgm.play();
                    musicToggle.textContent = '🔊';
                    musicToggle.classList.remove('muted');
                } else {
                    bgm.pause();
                    musicToggle.textContent = '🔈';
                    musicToggle.classList.add('muted');
                }
            });

            // 返回按钮逻辑 —— 防作弊：恢复全部默认态
            backToModeBtn.addEventListener('click', () => {
                // 重置模式变量
                currentMode = 'normal';
                spiritRootRollsLeft = 3;
                fortuneRollsLeft = 3;
                hardModeSpiritRootValue = "";
                customSelectedEntries = [];
                sessionStorage.removeItem(CUSTOM_FORTUNE_AUTH_KEY);

                // 清空所有输入框
                nameInput.value = '';
                genderInput.value = '';
                raceInput.value = '';
                appearanceInput.value = '';
                realmInput.value = '';
                realmSelect.value = '炼气期';
                identityInput.value = '';
                spiritRootTextarea.value = '';
                techniqueTextarea.value = '';
                fortuneInput.value = '';
                fortuneNameDisplay.textContent = '';
                customFortuneList.innerHTML = '';

                // 清空道侣字段
                companionNameInput.value = '';
                companionGenderInput.value = '';
                companionAppearanceInput.value = '';
                companionClothingInput.value = '';
                companionRaceInput.value = '';
                companionClassInput.value = '';
                companionPersonalityInput.value = '';
                companionAgeInput.value = '';
                companionAbilitiesTextarea.value = '';
                companionBackstoryTextarea.value = '';

                // 重置灵根
                spiritRootResult.textContent = '尚未觉醒...';
