            function getCustomPresets() {
                const stored = localStorage.getItem('daoyuanCharacterPresets');
                return stored ? JSON.parse(stored) : {};
            }

            function saveCustomPresets(presets) {
                localStorage.setItem('daoyuanCharacterPresets', JSON.stringify(presets));
            }

