            function applyPreset(data) {
                if (!data) return;

                if (data.currentMode && data.currentMode !== currentMode) {
                    transitionToCreation(data.currentMode);
                }

                document.getElementById('char-name').value = data.charName || '';
                document.getElementById('char-gender').value = data.charGender || '';
                document.getElementById('char-race').value = data.charRace || '';
                document.getElementById('char-appearance').value = data.charAppearance || '';
                document.getElementById('char-realm').value = data.charRealm || '';
                document.getElementById('char-realm-select').value = data.charRealmSelect || '未修炼';
                document.getElementById('char-identity').value = data.charIdentity || '';
                document.getElementById('char-spirit-root').value = data.charSpiritRoot || '';
                document.getElementById('char-technique').value = data.charTechnique || '';

                document.getElementById('fortune-name-display').textContent = data.fortuneNameDisplay || '';
                document.getElementById('char-fortune').value = data.charFortune || '';
                // 自定义气运：新格式 array，旧格式兼容单条
                customFortuneList.innerHTML = '';
                if (data.customFortunes && data.customFortunes.length > 0) {
                    data.customFortunes.forEach(cf => addCustomFortuneEntry(cf.name || '', cf.desc || ''));
                } else if (data.customFortuneName || data.customFortuneDesc) {
                    addCustomFortuneEntry(data.customFortuneName || '', data.customFortuneDesc || '');
                }

                hardModeSpiritRootValue = data.hardModeSpiritRootValue || '';
                if (hardModeSpiritRootValue && currentMode !== 'simple') {
                    spiritRootResult.textContent = hardModeSpiritRootValue.split('(')[0].trim();
