            const allFortunePools = () => [...trueFortunePresets, ...restrictedFortunePresets, ...allEroPresets];

            // ── 自定义气运多项管理 ──
            function createCustomFortuneEntry(name, desc) {
                const entry = document.createElement('div');
                entry.className = 'cf-entry';
                entry.innerHTML = `<div class="cf-entry-header"><span class="cf-entry-index"></span><button type="button" class="cf-delete-btn">✕</button></div>
                    <input type="text" class="cf-name" placeholder="气运名号，如：剑道独尊" value="${escapeHtml(name || '')}">
                    <textarea class="cf-desc" placeholder="气运描述">${escapeHtml(desc || '')}</textarea>`;
                entry.querySelector('.cf-delete-btn').addEventListener('click', () => {
                    entry.remove();
                    reindexCustomFortuneEntries();
                    syncAllFortunesToMvu();
                });
                entry.querySelector('input').addEventListener('blur', syncAllFortunesToMvu);
                entry.querySelector('textarea').addEventListener('blur', syncAllFortunesToMvu);
                return entry;
            }
            function addCustomFortuneEntry(name, desc) {
                const entry = createCustomFortuneEntry(name, desc);
                customFortuneList.appendChild(entry);
                reindexCustomFortuneEntries();
            }
            function reindexCustomFortuneEntries() {
                const entries = customFortuneList.querySelectorAll('.cf-entry');
                entries.forEach((el, i) => {
                    el.querySelector('.cf-entry-index').textContent = '气运 #' + (i + 1);
                });
            }
            function getCustomFortuneEntries() {
                const entries = [];
                customFortuneList.querySelectorAll('.cf-entry').forEach(el => {
                    const name = el.querySelector('.cf-name').value.trim();
                    const desc = el.querySelector('.cf-desc').value.trim();
                    if (name || desc) entries.push({ name: name || '未名气运', desc: desc || '' });
                });
                return entries;
            }
            function escapeHtml(str) { const d = document.createElement('div'); d.textContent = str; return d.innerHTML; }

            customFortuneAddBtn.addEventListener('click', () => addCustomFortuneEntry('', ''));

            function resolveFortuneEntries() {
                // 自定义气运优先级最高（多项）
                const customEntries = getCustomFortuneEntries();
                if (customEntries.length > 0) return customEntries;
                // 自选模式：用 customSelectedEntries
                if (customSelectPanel.classList.contains('active') && customSelectedEntries.length > 0) {
                    return customSelectedEntries.map(e => ({ name: e.name, desc: e.desc }));
                }
                // Roll模式：从显示文本解析
                const text = fortuneNameDisplay.textContent.trim();
                if (!text) return [];
                const matches = text.match(/【([^】]+)】/g);
                if (!matches) return [];
                const pools = allFortunePools();
                return matches.map(m => {
                    const name = m.replace(/【|】/g, '');
                    const found = pools.find(p => p.name === name);
                    return { name, desc: found ? found.desc : '' };
                });
            }
            async function syncAllFortunesToMvu() {
                if (!mvuReady) return;
                try {
                    const entries = resolveFortuneEntries();
                    const msgId = getCurrentMessageId();
                    const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                    if (!data || !data.stat_data) return;
                    const qiyun = {};
                    entries.forEach(e => {
                        qiyun[e.name] = { 类型: '被动', 效果: e.desc, 使用状态: '常驻', 剩余次数: null, 压制状态: '正常' };
                    });
                    _.set(data, 'stat_data.主角.气运', qiyun);
                    await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                } catch (err) {
                    console.warn('[道渊创建] 气运同步失败:', err);
                }
            }
