                { name: "真·鲲鹏宝术", desc: "入海为鲲，入天为鹏。阴阳共济，极速无双，肉身与法术皆是顶尖。" },
                { name: "真·六道轮回拳", desc: "一拳轰出，六道轮转，仿佛要将敌人打入轮回，霸道无边。" },
                { name: "真·大荒囚天指", desc: "半指撼天地，一指囚天地，五指动乾坤。指法通神，威力随修为指数级增长。" },
                { name: "真·莫欺少年穷", desc: "经典废材开局，遭受退婚羞辱。但只要定下三年之约，修炼速度将如坐火箭，必定打脸。" },
                { name: "真·赘婿战神", desc: "隐藏身份入赘修行世家，受尽白眼。待到一声令下，十万仙兵归位，让岳母后悔莫及。" },
                { name: "真·龙王归来", desc: "本是上界龙王，遭人陷害重生下界。标志性歪嘴一笑，生死难料，主要靠部下装逼。" },
                { name: "真·迪化流", desc: "明明很弱或平平无奇，但周围的人（包括敌人）总会脑补你是绝世高人，甚至能把你脑补成仙。" },
                { name: "真·稳健道祖", desc: "明明实力超群，却过分慎重。杀个练气期都要扬灰三天三夜，底牌永远掀不完。" },
                { name: "真·大爱仙尊", desc: "为人“真诚善良”，擅长“以理服人”。为炼春秋蝉，不惜献祭整条时间线（包括队友）。" },
                { name: "真·开局一条狗", desc: "身无分文，只有一条看起来像土狗的伴生兽。但这条狗其实是太古吞天兽，专吃神器。" },
                { name: "真·九龙拉棺", desc: "从天而降的青铜古棺带你开启星空古路，虽然开局凶险，但也是遮天大帝之路的起点。" },
                { name: "真·键盘侠道", desc: "以“键”入道，言出法随。只要在道理（喷人）上赢了对方，对方道心就会破碎，修为大跌。" },
                { name: "真·退婚流", desc: "被退婚后智商瞬间占领高地，原本的废柴体质觉醒，而且通常会捡到戒指里的老爷爷。" },
                { name: "真·我的宗主父亲", desc: "拼爹流极致，资源随便拿，闯祸有人兜。只要不作死招惹天命之子，基本横着走。" },
                { name: "真·扫地僧", desc: "宗门里最不起眼的扫地杂役，实际上是隐藏的太上长老，签到百年，出世即无敌。" },
                { name: "真·炸天帮众", desc: "行事乖张，喜欢抄家底。所到之处，寸草不生，连宗门地皮都给你刮走。" },
                { name: "真·科学修仙", desc: "用量子力学解释天道，用核聚变炼制金丹。当量即是正义，口径即是真理。" },
                { name: "真·我儿有大帝之姿", desc: "作为父亲/母亲，虽然自己资质平平，但儿子/女儿是绝世天才，能躺赢成太上皇。" },
                { name: "真·未婚妻是女帝", desc: "软饭硬吃。不仅未婚妻是转世女帝，而且极其护短，谁动你她灭谁满门。" },
                { name: "真·复活甲", desc: "拥有一种特殊体质或宝物，死后能原地满血复活，且每次复活都会变强（赛亚人？）。" },
                { name: "真·百分百空手接白刃", desc: "因果律技能。无论对方多强，只要你双手合十，对方的剑必定会砍在你手里，场面一度尴尬。" },
                { name: "真·恐怖如斯", desc: "作为旁白型气运，周围人总是对你的行为倒吸凉气，导致全球变暖（划掉），能震慑宵小。" },
                { name: "真·位面之子", desc: "运气好到不讲逻辑。跳崖捡秘籍，买破烂出神器，路边的乞丐都是隐世高人。" },
                { name: "真·种田流", desc: "拥有一方随身灵田，种出的灵植效果逆天。不争霸，只种地，最后用灵药堆死大BOSS。" },
                { name: "真·召唤流", desc: "自身战力一般，但能从异界召唤第四天灾（玩家）或动漫角色助战，打群架无敌。" },
                { name: "真·天道是我妈", desc: "你乃天道私生子，亲妈。渡劫？雷劫自动绕路。瓶颈？亲妈给你开小灶。气运之子？在你面前就是个弟弟。" },
                { name: "真·绝对闪避", desc: "因果律级别的闪避能力。任何形式的攻击，在命中你之前都会因为各种匪夷所思的原因（如敌人脚滑、时空扭曲）而打偏。" },
                { name: "真·驯兽之神", desc: "任何兽类，无论凡兽、灵兽还是神兽，见到你都会被你身上神圣的亲和力所吸引，自愿成为你最忠诚的仆从，连混沌巨兽都抢着给你当坐骑。" },
                { name: "真·一气化三清", desc: "道门至高神通，能化出两个与本体实力完全相同的分身。相当于三倍战力，而且分身还能各自修炼，经验共享。" },
                { name: "真·背景板之王", desc: "虽然你看起来平平无奇，但你的书童是剑仙转世，养的狗是上古凶兽，家里的老黄牛是神兽。谁惹你谁倒霉。" },
                { name: "真·无限蓝条", desc: "你的灵力/法力是无限的。你可以毫无顾忌地释放任何消耗巨大的禁咒或神通，用大招洗地是你的常规操作。" },
                { name: "真·百倍时间流速", desc: "你拥有一个个人空间，里面的时间流速是外界的一百倍。你在里面修炼百年，外界才过去一年。" },
                { name: "真·人生剧本", desc: "能看到所有人（甚至万物）的命数与近期机缘。不仅能截胡天命之子的逆天造化，还能时刻趋吉避凶。" },
                { name: "真·情绪值系统", desc: "收集他人的喜怒哀乐化为神力。只要不断搞事情让人破防或震惊，修为资源就能源源不断地兑换。" },
                { name: "真·诸天万界钓鱼", desc: "抛竿入虚空，法宝、神丹甚至太古神女都能钓上来。运气好一杆子钓出隔壁世界的镇族至宝。" },
               { name: "真·杀敌掉宝狂魔", desc: "将现实世界网游化。击杀任何生灵必爆满地散发金光的极品装备和修为光球，舔包就能天下无敌。" },
                { name: "真·反伤刺甲", desc: "纯粹的血牛防战流。完全放弃攻击，遭受任何伤害皆可十倍奉还。" },
                { name: "真·万界外卖员", desc: "骑着小电驴穿梭于诸天送外卖。不仅结交各界大佬，获得的神级打赏更是让人连连突破小境界。" },
                { name: "真·御兽合成术", desc: "左手一只土狗，右手一只麻雀，双手一拍直接合体为不可名状的灭世神兽，宠物全靠乱炖。" },
                { name: "真·最强典狱长", desc: "随身带着一座神话监狱，里面关押着大量曾经镇压时代的女帝和女魔尊，可以随时抽取他们的力量或放出来当打手。" },
                { name: "真·大召唤术", desc: "遇事不决直接献祭节操。能跨次元召唤各种动漫、影视或者科幻神话里的巅峰战力过来替你群殴别人。" },
                { name: "真·死亡回档", desc: "每次死亡都会自动连带记忆回到一天前。拥有无限试错的权利，硬生生用无数次死亡堆出完美的通关结局。" },
                { name: "真·万界当铺", desc: "开设神秘当铺，收取他人的气运、天赋甚至爱情作为典当物发放贷款。一旦违约直接抹杀并吞噬其一切。" },
                { name: "真·负能量大师", desc: "靠收集怨念变强。每天在修仙界疯狂群嘲，做尽缺德事，整个修仙界恨你入骨。" },
                { name: "真·双修十倍增幅", desc: "虽然不是合欢宗，但任何人与你双修都能获得极尽升华的十倍回馈，直接引得天下所有仙子圣女对你倒贴疯抢。" },
                { name: "真·超级投资大鳄", desc: "四处寻找处于落魄期和退婚期的气运之子进行投资，等他们起飞后获得百倍回报，小弟遍布九天十地。" },
                { name: "真·诸天拍卖会", desc: "掌控一家只在传说中存在的跨界客栈，定期拍卖各界无人能及的至高大机缘，把世界的大能玩弄于股掌之间。" },
                { name: "真·老爷爷收容所", desc: "别人的戒指里只有一个老爷爷，你的识海里住着百八十个不同体系的远古残魂和仙帝意志，什么流派都能随便给你挑。" },
                { name: "真·时间掌控者", desc: "随意操纵时间的流逝，可以直接暂停时间暴打强敌，或者在时间长河中漫游回到过去把敌人还在娘胎里时扼杀。" },
                { name: "真·炼蛊大宗师", desc: "抓天地各种极品奇虫灵材炼制无解仙蛊。哪怕是一只蚊子经你之手，也能化作一旦放出便毒绝天下的灭世蛊王。" },
                { name: "真·机械飞升", desc: "抛弃血肉苦弱，掌控诸界科技之树。用植入仙道核心的机械神躯布阵，并且用跨星系轨道炮来轰毁自己的成仙雷劫。" },
                { name: "真·九幽地狱之主", desc: "天生号令地狱黄泉无数恶鬼阴兵，你施展的每一击都附带着十八层地狱的凄厉诅咒和能瞬间撕裂魂魄的精神冲击。" },
                { name: "真·杀戮通缉榜一", desc: "因系统机制脑袋顶上永远挂着全诸天最昂贵的通缉令。全世界的人都想来杀你，但你反杀敌人后获得的修为奖励却极其离谱。" },
                { name: "真·神话缔造者", desc: "你可以随心所欲在修仙界普及地球上的神话故事。你只要编造得越逼真，那传说中的人物和神器就会强制实体化并唯你是从。" },
                { name: "真·两界穿梭门", desc: "能够自由穿梭在一个毫无灵气的现代蓝星和一个极度危险的修真界之间。通过两界的科技与物资倒买倒卖，直接轻松躺平逆天。" },
                { name: "真·最强吃软饭", desc: "专门绑定大世界中冷傲女帝和绝代神女，只要用花言巧语哄得她们心花怒放，你的各项属性值就会以几何倍数狂暴飙升。" },
                { name: "真·神蛋孵化者", desc: "开局系统送颗能吸干宗门灵脉的超级宠物蛋。孵出看似普通的弱小宠物，最终却会化作能够一口吞噬漫天星河的太古巨兽。" },
                { name: "真·雷劫代打服务", desc: "对所有雷法天然免疫。专门帮渡劫期老怪代扛天劫，不仅能收得天价手续费，还能把天道轰下来的劫雷压缩进瓶子里当手榴弹扔。" },
                { name: "真·宗门基建狂魔", desc: "起步只有一个破落茅草屋，通过到处诓骗拥有奇葩体质的弟子入门，一步一步把野鸡宗门打造成让仙帝都只能在门外扫地的无上圣地。" },
                { name: "真·神豪大撒币", desc: "奉行“有钱就是可以为所欲为”的大道。花出去的灵石越多，系统返回给你的修为加成和神器奖励就越恐怖。" },
                { name: "真·时空大盗", desc: "谁敢惹你，你不打他，你直接通过时空隧道回到亿万年前，把那强敌祖坟里的机缘全挖走，导致那个牛逼轰轰的敌人现在瞬间萎缩成了废物穷光蛋。" },
                { name: "真·被迫脑补大帝", desc: "明明只想做个苟在山沟里的低调路人甲，奈何系统和运气总是让你在最恰好的时刻引发毁天灭地的宏大异象，硬生生受尽诸天万界的狂热顶礼膜拜。" },
                { name: "真·极限作死系统", desc: "在悬崖边反复横跳。系统规定你作的死越大、引起的仇恨越恐慌，你得到的反馈奖励就越疯狂爆表。" },
                { name: "真·神级诸天穿梭", desc: "完全无视位面大道的空间壁垒阻拦。如果在这个高武仙侠世界惹到了全宇宙的满门通缉打不过时，瞬间就能跑路躲避到漫威科幻或者灵气刚复苏的都市世界里，去虐菜发育满级了再回来报仇碾压。" },
               { name: "真·降智光环", desc: "发动后强行将方圆万里内所有生灵的智商拉低到和你同一水平，然后利用你多年身经百战的弱智经验击败他们。" },
{ name: "真·强制尬舞", desc: "因果律绝对控场。只要你掏出特制音响播放BGM，范围内所有人都必须陪你跳完一首完整的广场舞，期间修为全部封印。" },
{ name: "真·拼夕夕砍一刀", desc: "面临无法突破的瓶颈或恐怖天劫时，可将伤害或雷劫分享给诸天万界99.9%的修士平摊，每人只掉一根头发，你度过难关。" },
{ name: "真·天道税务官", desc: "被系统赋予收税权。只要敌人在你面前呼吸或运转真气，就必须自动向你缴纳20%的“灵气消费税”，打得越久对方越穷。" },
{ name: "真·薛定谔的队友", desc: "因果律反转机制。你对敌人释放加血技能会造成真伤暴击，对队友释放杀招反而能生死人肉白骨，让敌人的防御意识彻底崩溃。" },
{ name: "真·言出必反", desc: "顶级毒奶体质。只要你真诚地祝愿敌人“万寿无疆长生不老”，五分钟内对方必定天降陨石横死当场。" },
{ name: "真·万界差评师", desc: "只要你在战斗中对敌人的绝招、法宝或长相给出“一星差评”，该技能/物品的效果将被天道强行削弱90%。" },
{ name: "真·云养徒弟", desc: "无需亲自传授，随意绑定天才认作云徒弟。他们在外界九死一生获得的机缘和修为，会在云端自动复制一份打入你的体内。" },
{ name: "真·强制马赛克", desc: "视觉概念打击。敌方发出的任何华丽究极仙法，在靠近你时都会被天道认定为“违规画面”而打上厚重的马赛克，导致毫无杀伤力。" },
{ name: "真·物理超度", desc: "一切法术豁免。你只能使用名为“南无加特林菩萨”的法器，一息三千六百转，大慈大悲度世人，口径即是正义。" },

{ name: "真·微信步数修仙", desc: "完全不需要打坐，每走一步就自动增加一点修为。只要你是个路痴，飞升不是梦。" },
{ name: "真·吃瓜群众", desc: "只要你在手中变出一块西瓜并开始啃，你将处于绝对的“无法选中”状态，看神仙打架连余波都伤不到你一根汗毛。" },
{ name: "真·进度条窃贼", desc: "能直观看到敌人大招的读条时间。只需伸手一偷，对方苦苦憋了三天的绝杀读条瞬间归零，还要承受技能反噬。" },
{ name: "真·Ctrl+Z法则", desc: "每天一次的因果律撤销键。无论你刚刚犯了什么滔天大错或被人秒杀，一键回退到三秒前你还能抢救一下的时候。" },
{ name: "真·甲方爸爸", desc: "获得直面天道的无理取闹权。天劫噼下来时，你可以大喊反驳：“这个雷劫颜色不行，不够大气，给我回去改一版再发设！”天雷直接憋回去。" },
{ name: "真·被动碰瓷", desc: "绝对正当防卫机制。敌人只要用眼神瞪你一下，只要你当场倒地口吐白沫，天道雷罚就会以“蓄意伤人罪”把对方劈成飞灰。" },
{ name: "真·百分百空手接白刃·变种", desc: "无论敌方使用毁天灭地的剑阵还是万尺巨剑，只要你双手合十，不仅能夹住剑，敌人还会不由自主地瞬移过来双膝下跪配你摆造型并叫爸爸住手。" },
{ name: "真·取名废的诅咒", desc: "在交战时强行给敌人起一个屈辱的绰号（如：二傻羊）。只要绰号叫出口，对方的真名和血脉将被天道强行窜改成该绰号。" },
{ name: "真·概念偷换", desc: "你能篡改世界字典。打响指将“受伤”与“大补”的概念互换，敌人对你疯狂输出，只会让你舒服得突破大境界。" },
{ name: "真·全损画质", desc: "降维打击法门。发动后，敌人的视界、功法包括肉身都会被强行压缩成8比特马赛克像素风，变成一堆行动缓慢的方块。" },

{ name: "真·静音模式", desc: "一键屏蔽世界频道。在这个结界里，任何需要吟唱、咆哮、或者喊出招式名的法术都会因为“发不出声音”而施法失败。" },
{ name: "真·高利贷魔尊", desc: "强制让敌人借你的灵气。不用你打，利滚利的因果业障会在一天内吸干他们全宗门的百分之三十蕴来还天道利息。" },
{ name: "真·防沉迷系统", desc: "你犹如天堑。任何试图与你交战的敌人，每天只能对你造成1.5小时的伤害；超时后强制进入疲劳期，伤害为零且只掉1滴血。" },
{ name: "真·水军控评", desc: "召唤上千万看不见的键盘侠残魂。在敌人耳边24小时不停地进行全方位无死角的言语辱骂和造谣，直到对方道心崩溃自尽。" },
{ name: "真·强买强卖", desc: "扔给绝世大帝一块路边捡的石头，天道法则会强制判定这是一场绝世交易，并将大能身上最贵的物品强行传送给你。" },
{ name: "真·万物皆可盘", desc: "哪怕是砸向你的星辰陨石，只要在你手里盘久了，都会被盘包浆，变成毫无杀伤力的文玩核桃。" },
{ name: "真·路痴的奇迹", desc: "方向感越差运气越好。只要你坚定地往反方向走，总能一头撞进未开发的仙家遗迹或者直接瞬移到敌人老祖的澡堂里。" },
{ name: "真·无痕浏览", desc: "因果律极道隐身。不仅斩断一切过去未来的推演，连你在路上走过都不会留下脚印。杀完了人，受害者的记忆里都是“我是自杀的”。" },
{ name: "真·天道代驾", desc: "当你面对打不过的首领时，直接双眼一翻“失去意识”，让冷酷无情的天道主机代打你的身体，招招致命计算精确到小数点后六位。" },

{ name: "真·数学打击", desc: "开启学霸领域。敌人释放神通前必须先在脑海中解开一道微积分大题，答错或者超时，体内灵力立刻走火入魔剧烈爆破。" },
{ name: "真·阅读理解", desc: "甩出一句毫无意义的废话，敌人及其智囊团会强迫自己熬夜分析你的“弦外之音”，甚至能脑补出一套自我毁灭的阴谋逻辑去执行。" },
{ name: "真·PPT施法", desc: "强行将周围的现实空间降帧。你是在正常战斗，而在你的敌人看来，整个世界的画面是一秒一卡，大招刚按出来，头已经飞了。" },
{ name: "真·摸鱼光环", desc: "辐射散发极限怠惰气息。只要靠近你十米范围，无论是嗜血魔尊还是复仇狂魔，都会瞬间觉得人间不值得，只想找张床躺下直接摆烂。" },
{ name: "真·天道打卡机", desc: "每天早上九点到指定坐标签到打卡，即可获得持续8小时的“工作时间无敌保护罩”，下班后直接跑路，没谁能留得住你。" },
{ name: "真·强制配对", desc: "面对两个围攻你的绝顶高手，红线一牵，两人瞬间坠入无可救药的狂热爱河，立刻放弃战斗当场私奔归隐山林。" },
{ name: "真·复制粘贴", desc: "不需要看懂任何玄奥繁杂的功法，只需对着敌人施法动作按下心中 Ctrl+C，然后 Ctrl+V，无论多逆天的招式立即完美顺发反打回去。" },
{ name: "真·垃圾分类", desc: "你的右眼能精准识别所有生灵是“干垃圾”、“湿垃圾”还是“有害垃圾”。被你判定为垃圾后，丢进指定的概念垃圾桶直接秒杀抹除。" },
{ name: "真·地狱笑话", desc: "讲出一个伤天害理的地狱修仙笑话。如果天道听了觉得太过分降下灭世狂雷劈你，而那道雷100%会精确制导劈中挡在你前方的敌人。" },
{ name: "真·强迫症之怒", desc: "只要敌人的阵法不完全对称，或者防御法宝有哪怕一根毛刺划痕，你对他的暴击率和暴击伤害将直接飙升10倍！" },
{ name: "真·延迟伤害", desc: "锁血挂的极致应用。无论今天你被打成什么惨状，都可以使用因果律把当前所受的致命伤害转移给“明天”的自己。" },
{ name: "真·强制下线", desc: "直接把“断开连接”的概念施加在敌人身上。正打着架，这名大能突然因为“网络波动”在现实中凭空消失五分钟任你摆布。" },
{ name: "真·精神损失费", desc: "任何人对你发动幻术、神识攻击或进行言语嘲讽辱骂，其修仙资源、灵石和寿元就会自动以每秒1颗的速度转入你的储物戒中。" },
{ name: "真·广告植入", desc: "在敌人马上要打中你的极限时刻，强行停止整个世界的时间，并给敌人播放一段不可跳过且声量极大的15秒拼刀刀广告，打断所有施法动作。" },
{ name: "真·美颜滤镜", desc: "将自身的魅力和颜值调至于天道不容的“MAX+++”级别。任何人看你一眼就会因为不可名状的极度完美而永久性精神失常和致盲。" },
{ name: "真·物理静音", desc: "你的一板砖自带“绝对禁魔”属性。不需要破阵决法，只要一砖精准地拍在别人后脑勺上，即便是大能也别想再念出半个字的法诀。" },
{ name: "真·同天同月同日死", desc: "把自己的命格直接跟天道强行绑定在一起。一旦你死了，诸天万界直接坍缩重启。从此以后全天下的反派都要拼死拼活保护你的安全。" },
{ name: "真·强行加戏", desc: "无论是不关你事的两人决战，还是大能争夺绝世珍宝，你总能以离谱和戏剧化的方式突然掉入场中，并在法则影响下成为全场最核心的焦点。" },
{ name: "真·一键清空回收站", desc: "抹杀概念上的根须复活。任何被你击杀的人、妖、鬼、魔，只要你按下虚空中的“清空选项”，所有转世手段、灵魂烙印统统灰飞烟灭！" },

{ name: "真·知识就是力量", desc: "字面意思。把千万本厚重晦涩的藏经阁玉简直接具象化为物理板砖。你看过的书越多，你砸人的书就越重，一发《词典》重如泰山。" },
{ name: "真·断网遁法", desc: "无论被困在多么可怕的十死无生杀阵还是次元牢笼中，只要你做出“拔网线”的动作，就能立刻掉线退回安全大本营。" },
{ name: "真·借条法则", desc: "当敌人试图用大招轰击你时，你直接递出一张欠条。敌人的大招伤害会被转换为同等数额的债务，必须等他还清债务才能真正生效打疼你。" },
{ name: "真·伪造天意", desc: "通过在山洞石壁上刻字、在鱼肚子里塞帛书这种极廉价的手段，被天道承认为真正的预言，让整个修仙界为此疯狂厮杀。" },
{ name: "真·打假斗士", desc: "你的存在就是撕破虚伪，敌方平时为人越是满口仁义道德、背地男盗女娼，被你一剑戳穿时遭受的真实比例伤害就越恐怖。" },
{ name: "真·量子波动速读", desc: "面对一门深奥无比必须要领悟十万年才能大成的绝世功法秘籍，你只要拿着书像吹风扇一样哗啦啦翻上两秒钟，直接顿悟大圆满。" },
{ name: "真·走近科学", desc: "你坚定的唯物主义让玄幻唯心破灭。只要你能用牵强的科学原理解释出敌人的术法（哪怕是胡扯的量子力学），该法术原地失去超自然威力。" },
{ name: "真·退群保平安", desc: "眼看所在宗门即将大祸临头或被诸神围剿，只要你高喊一句“我退出！”，因果关系瞬间抹除，万千敌人会自动将你判定为不相关的吃瓜路人。" },
{ name: "真·一键还原", desc: "眼看局势不对，拍下按钮，把整个战场方圆百里的地形、所有人的状态和生命值全部无伤复原到三个时辰之前，假装无事发生重新来过。" },
{ name: "真·免责声明", desc: "动手之前让敌人按下一个手印。如果对方死了，即便是其背后的大能，在看到这份免责声明时也会因为因果律束缚而无法报复你。" },

{ name: "真·按键精灵", desc: "把枯燥的挥剑、炼丹或躲避动作录制成一段宏。睡着了身体也能自动按照路线每零点一秒鬼畜地完美执行格挡反击，且永远不知疲惫。" },
{ name: "真·强制拔网线", desc: "将敌人与天地灵气之间的联系视作一根隐形的光缆。只要手一狠掐断因果网线，面前高高在上的大能当场变成没有半点修为的凡夫俗子一分钟。" },
{ name: "真·打光师", desc: "因果律特效。自带无源头的神圣逆光与探照大灯。只要你出场，无论环境多黑，你都亮的像个灯泡，让习惯暗杀的刺客直接闪瞎双眼痛苦哀嚎。" },
{ name: "真·弹幕护体", desc: "将你前世的所有网络回帖化为实体盾牌。你喷过的人越多，护盾越厚；千万条键盘侠怨念弹幕绕身旋转，万劫不落。" },
{ name: "真·氪命玩家", desc: "献祭自己百分之八十的寿命，换取一秒钟的无敌帧和攻击力暴增100倍。" },
{ name: "真·反向重力牛顿", desc: "周围重力随着你心情随便篡改，不仅能把敌人的血全冲到脑子里令其爆血管，还能借由重力让所有暗器投掷物自动掉落拐弯。" },
{ name: "真·灵魂画手", desc: "在沙地上用棍子画一个火柴人，指代敌方大能。无论画得多么抽象，消耗自身的全部修为，只要你用脚抹去火柴人的脑袋，相隔千万里的大能当场人头落地。" },
{ name: "真·跨服拉黑", desc: "面对无法战胜的存在不必恐慌。只需使用大因果拉黑术。你看不见他，同样的，在他的认知里你也从世上被永久抹去，永远相安无事。" },
{ name: "真·无限套娃", desc: "肉身被毁时，会从尸体里跳出一个体型缩小10%但满血状态的本体。只要不被嫌小，理论上可以无限续命。" },

{ name: "真·共享单车法则", desc: "当你需要赶路或逃跑时，无论荒山野岭还是魔界深渊，随时都能在路边顺走一头别人停放着的绝世神兽当坐骑，用完还不用还。" },
{ name: "真·强买强卖的祝福", desc: "遇到濒死的修士强行往他嘴里塞神药，救活后系统会自动评估命权价值，掏空对方甚至全宗门宝库支付你的“急诊医药费”。" },
{ name: "真·自动寻路", desc: "不用费心破除各种奇门遁甲迷宫杀阵。闭上双眼，双脚宛若失去重力般自动漂移滑动，一路精确规避所有暗箭陷阱直接抵达大反派卧室。" },
{ name: "真·强制和解", desc: "撒出漫天白鸽。方圆十里内的狂暴妖兽、嗜血魔头和正道名宿，在受术瞬间统统放下屠刀立地变成围在一起织毛衣的慈祥狂热和平主义者。" },
{ name: "真·天道VIP通道", desc: "万界出行均享有头等舱待遇。过空间裂缝不会颠簸，遇到天劫可以花尊贵特权直接点‘跳过’，连去十八层地狱报到都不用排队。" },
{ name: "真·天气预报倒带", desc: "只要出门没带伞，就能强行倒转整片大陆星系的时空，回到三分钟前天气晴朗的时候，一切大能战斗的时空悖论都不如你别淋湿衣服重要。" },
{ name: "真·背锅大侠", desc: "当你想做尽坏事却又图个清净时，无论你干了啥缺德事，案发现场总会奇迹般地留下另一个死对头的独门功法气息和铁证如山的身份证件。" },
{ name: "真·一键清空记录", desc: "当你社会性死亡，或者不小心暴露底牌时，全图释放记忆清空。在场所有生灵集体断片丢失过去五分钟的记忆，且无法察觉任何异样。" },
{ name: "真·反差萌光环", desc: "不管你杀人手段多么残忍，砍人的样子多么狰狞。在别人眼里都会自动加上粉红滤镜，觉得你是个心地善良、傲娇惹人怜爱的软萌修士，不仅不报复，还要保护你。" },
{ name: "真·随机封号", desc: "你的系统每半年会给你一个“封号包”。看谁不爽直接扔过去，对方将在24至72小时之内丹田闭塞、神识锁死、完全变成一个废人。" },
{ name: "真·一键换装", desc: "无视空间定律，瞬间把全副武装冲过来的敌人的极品装备全部扒光，替换成一件性感的粉色比基尼，直接对其造成破甲和精神暴击。" },
{ name: "真·外星语压制", desc: "你释放的所有法术口诀都由外星乱码构成。因为敌人无法理解你的体系语言，他们身上任何针对本界法则的魔法抗性和护盾统统如纸糊般失效。" },
{ name: "真·强制休假", desc: "朝敌人扔出一张沙滩椅。法则强迫他在躺椅上安详入睡享受三个月的带薪年假，就算是天道也别想叫醒一个正在休假的大魔王。" },
{ name: "真·网恋奔现诅咒", desc: "对单身大反派使用。必定使得反派苦恋多年的“圣女白月光”笔友真实身份变成抠脚大汉，让恶鬼因心碎丧失全部战斗力。" },
{ name: "真·物理净化", desc: "你倒出的不是寻常净化之水，而是极度浓缩高纯度工业酒精与次氯酸钠混合液，被泼到的阴魂邪祟当场燃烧物理超度，连骨灰都不剩渣。" },
{ name: "真·强行剧透", desc: "趴在敌人耳边，将对方苦心孤诣谋划了十万年的完美结局直接全部说穿。导致对方人生乐趣直接失去意义，道心破碎，原地解脱。" },
{ name: "真·自带BGM", desc: "自带不可见的百万级百万瓦立体音响。在你的专属背景音乐《好汉歌》播放完毕之前，你受到的任何伤害强制变为零，且拥有霸体状态。" },
{ name: "真·错别字大能", desc: "你能改写万物法则里的同音字。大喝一声将敌人的“排山倒海”改成“排山倒鞋”，眼看着无穷无尽的破草鞋将敌人自己活活埋起来熏死。" },
{ name: "真·无限反转法", desc: "无论你陷入多么绝对必死的绝境（如脑袋已经被砍下来了），只需对着天道轻蔑一笑说声“看来你不过如此”，必定触底反弹触发奇迹大局逆转挂。" },
{ name: "真·强行入梦", desc: "打不过对方现实的修为？直接把两人同时拉入你的梦境！在你的梦里你是无敌的存在，直接把大能捏成尖叫鸡任意揉搓把玩。" },
{ name: "真·百分百借钱成功", desc: "遇到神豪仙二代，只要你开口说“借我两块极品灵石周转”，不可抗拒的因果律会逼迫对方双手奉上家底全副财产甚至裤衩子。" },
{ name: "真·天命收割机", desc: "你手中的死神镰刀无视肉体防御，专砍敌人头顶无形的气运光柱。一刀下去气运清零，对方上一刻还是位面之子，下一秒喝口水都能噎死。" },
{ name: "真·打卡下班遁", desc: "时间一到酉时正刻(下午五点)，天地法则瞬间加持，你的速度提升亿万倍，无人能拉住你加班厮杀，连追击的仙帝也只能对着你的残影吃尾气。" },
{ name: "真·脑洞具现", desc: "在面临无解困境时，只要你在脑子里进行最荒唐、最不可能的无厘头幻想（比如天生掉下一头塞满炸药的粉色大象砸死敌人），天道就必须让它实现并合理化。" },
{ name: "真·强制卸妆水", desc: "因果泼洒。不管是法相金身、易容术还是夺舍肉身，沾到一滴立刻溶解为最原始的脆弱真灵丑态，防御彻底瓦解。" },
{ name: "真·万法皆下品惟有读书高", desc: "启动该气运后，附近万里的灵气溃散只存在浩然之气。修仙大能们辛辛苦苦炼的法宝全部变成废铁，必须和你考一局四书五经，分数低的当场暴毙。" },
{ name: "真·同归于尽打消术", desc: "眼看反派要自爆拉你一起下海，你轻轻一句“何必呢”，反派瞬间觉得自己这么多年的奋斗非常可笑，直接吹散真气选择出家当和尚。" },
{ name: "真·天道白条", desc: "穷到没灵石了？直接向天意签立白条预支一座灵石矿在身上。至于什么时候还……还钱那是几十个元会后你转世以后的事了，关现在的你屁事。" },
{ name: "真·薛定谔的秘籍", desc: "路边随便捡的一张废纸。只要你不翻开，它就一直处于“绝世神功”和“擦屁股纸”的叠加态。只要你深信不疑它是神器，它就能发挥出神器的效果。" },
                { name: "真·天赋掠夺", desc: "每当你杀死一个生灵，你都能从其身上随机掠夺一项天赋或神通，并能完美融合，无任何副作用。" }
            ];

            const restrictedFortunePresets = [
                { name: "天命反派", desc: "天生站在主角对立面。虽修行速度极快，但容易招惹气运之子，稍有不慎便会成为他人踏脚石。" },
                { name: "天命大反派", desc: "心性狠辣，行事无所顾忌。虽能通过掠夺快速变强，但举世皆敌，正道人人得而诛之，难以寻找盟友。" },
                { name: "尸道宗师", desc: "常年与尸体为伍，自身生机被死气侵蚀。虽控尸之术了得，但肉身阴寒，不仅由于外貌被排斥，且难以修习正统阳刚功法。" },
                { name: "不化骨", desc: "肉身坚硬如铁，刀枪不入，但关节僵硬，身法迟缓。需大量阴煞之气温养，且化形困难，易被当做妖魔斩杀。" },
                { name: "黄泉引路人", desc: "能通幽冥，役鬼神。但每次开启鬼门都会沾染因果，易招致阴邪反噬，晚年恐遭不详。" },
                { name: "每日签到系统", desc: "拥有签到系统，但奖励多为凡俗之物，极少出现珍品。且系统发布任务强制性强，若不完成会有厄运缠身。" },
                { name: "深蓝加点", desc: "可通过消耗资源强制提升功法境界，但根基虚浮，战力低于同阶苦修者。需花费额外精力打磨心境，否则易走火入魔。" },
                { name: "人生模拟器", desc: "可模拟未来，但每次模拟消耗海量灵石与精神力。且模拟中的死亡阴影会影响现实道心，需长时间恢复。" },
                { name: "授徒万倍返还", desc: "返还倍率极不稳定，多为低倍率。且徒弟资质参差不齐，教导徒弟极其耗费心力，严重拖慢自身修炼进度。" },
                { name: "神级选择系统", desc: "选项往往充满陷阱，高风险高回报。虽然奖励丰厚，但常被迫卷入大能纷争或绝地险境，九死一生。" },
                { name: "最强反套路", desc: "行为必须异于常人才能获得力量，常被人视为疯子或哗众取宠之辈。难以在宗门体系中安稳生存，名声狼藉。" },
                { name: "功法简化系统", desc: "功法易学难精，虽入门极快，但威力打了折扣。且简化版功法往往存在隐患，上限锁死，难以突破至最高境界。" },
                { name: "诸天聊天群", desc: "群成员鱼龙混杂，真假难辨。跨界交易需支付高昂代价，且容易被高位面存在顺着网线（因果线）进行降维打击。" },
                { name: "挂机修仙", desc: "身体自动修炼，但由于没有神识主导，遇到瓶颈无法自动突破。且挂机时对外界感知降低，容易遭遇偷袭。" },
                { name: "吞噬进化", desc: "可通过吞噬万物变强，但体内杂质淤积，需花费大量时间炼化。若贪得无厌，终将化为只知进食的怪物。" },
                { name: "长生词条", desc: "寿元无尽，但资质奇差无比。修炼速度如龟爬，只能坐看沧海桑田，亲友离世，承受无尽的孤独岁月。" },
                { name: "直播修仙", desc: "通过人气获取资源，但行踪完全暴露。仇家可随时掌握你的动向，且为了人气不得不去险地作死，毫无隐私可言。" },
                { name: "家族修仙", desc: "家族是助力也是枷锁。享受资源的同时，必须承担繁重的家族责任。一旦家族卷入纷争，自身也难以独善其身。" },
                { name: "氪金成仙", desc: "哪怕呼吸都需要消耗灵石。没有灵石寸步难行，修为会随财富减少而倒退。终其一生都在为赚取灵石而奔波。" },
                { name: "任务狂魔", desc: "被迫接受各种繁琐任务，无法长时间闭关。任务奖励虽然稳定，但难度逐渐失控，常被迫中断修行去跑腿。" },
                { name: "至尊骨", desc: "曾被挖去至尊骨，虽涅槃重生但元气大伤。体质虚弱，需海量天材地宝填补亏空，方能重现至尊神威。" },
                { name: "重瞳者", desc: "看破虚妄，但对神魂消耗极大。常年处于精神疲惫状态，且容易看到不该看的大恐怖，导致精神失常。" },
                { name: "混沌体", desc: "万气皆可修，但进阶所需资源是常人的百倍。在资源匮乏的修仙界，极易因为资源不足而卡在低境界蹉跎一生。" },
                { name: "荒古圣体", desc: "肉身无双，但被天地法则压制，不仅突破艰难，且是消耗源石的无底洞。晚年易发生不详异变。" },
                { name: "先天道胎", desc: "天生近道，情感淡漠。随着修为加深，人性逐渐丧失，最终可能被天道同化，成为无情无欲的规则化身。" },
                { name: "苍天霸体", desc: "霸道绝伦，但性格偏激易怒，容易被激将法利用。且霸体之血乃是魔修眼中的无上大药，常遭觊觎。" },
                { name: "仙帝转世", desc: "空有高深境界的感悟，肉身却孱弱不堪。眼高手低，极易因为轻视低阶修士而阴沟翻船，且背负前世因果仇恨。" },
                { name: "伴生帝兵", desc: "帝兵受损严重，需吸食宿主精血温养。在修复之前，它不仅无法护主，反而是个巨大的累赘和定时炸弹。" },
                { name: "鸿蒙紫气", desc: "成圣之基，引得天下修士疯狂。怀璧其罪，举世皆敌，在成长起来之前只能隐姓埋名，东躲西藏。" },
                { name: "三足金乌", desc: "身具太阳真火，掌控至阳之道，化身大日，焚煮江海只在一念之间。" },
                { name: "祖龙血脉", desc: "肉身强横无匹，统御水族，一声龙吟万兽臣服，天生自带龙威。" },
                { name: "他化自在", desc: "借取未来果位需支付巨大代价，每次使用后会陷入长时间的虚弱期。且容易迷失在无数个“自我”之中，分不清虚幻现实。" },
                { name: "皆字秘", desc: "十倍战力触发概率极低，如同赌博。关键时刻若未触发，便只能任人宰割。且对身体负荷极大。" },
                { name: "九秘合一", desc: "强行融合九秘极易导致体内灵力紊乱。非大毅力、大机缘者，不仅无法发挥威力，反会经脉寸断而亡。" },
                { name: "源天师", desc: "寻龙点穴，泄露天机。晚年必遭不详，全身生红毛，神智迷失，成为游荡在禁区的人形怪物。" },
                { name: "神象镇狱", desc: "肉身成圣之路，每觉醒一颗微粒都需吞噬一方资源的能量。在资源贫瘠之地，此功法形同废纸。" },
                { name: "佛怒火莲", desc: "玩火自焚。融合异火极其危险，稍有差池便是灰飞烟灭。且异火难寻，往往存在于绝地之中。" },
                { name: "草字剑诀", desc: "剑意凌厉伤人伤己。修习此剑诀者，身体常年承受剑气切割之痛，寿元较同阶修士更为短暂。" },
                { name: "鲲鹏宝术", desc: "阴阳二气难以调和。在化鹏与化鲲之间切换时存在僵直期，易被敌人抓住破绽。且食量惊人。" },
                { name: "六道轮回拳", desc: "拳意霸道，每一拳都在透支生命潜能。年轻时威震天下，年老时气血枯败，往往不得善终。" },
                { name: "大荒囚天指", desc: "威力巨大，但蓄力时间过长。在瞬息万变的生死搏杀中，极易被打断施法或成为活靶子。" },
                { name: "莫欺少年穷", desc: "本是众人眼中的废物，又遭退婚之辱。立下三年之约，只能比从前更刻苦修行，能否翻身仍是未知。" },
                { name: "赘婿战神", desc: "隐藏身份入赘修行世家，受尽白眼。待到一声令下，十万仙兵归位，让岳母后悔莫及。" },
                { name: "龙王归来", desc: "本是上界龙王，遭人陷害重生下界。标志性歪嘴一笑，生死难料，主要靠部下装逼。" },
                { name: "迪化流", desc: "自身实力平平，全靠他人脑补。如同在钢丝上行走，一旦露馅，之前建立的威望将瞬间崩塌，死无葬身之地。" },
                { name: "稳健道祖", desc: "过分谨慎，错失机缘。因害怕沾染因果而不敢出门，虽然活得久，但修为进境极其缓慢，难以登顶。" },
                { name: "大爱仙尊", desc: "为达目的不择手段，虽获利颇丰，但道心逐渐扭曲。终日活在算计与被算计之中，再无半个可信之人。" },
                { name: "开局一条狗", desc: "伴生神兽处于幼年期，不仅战力低下，还是个吞金兽。常常偷吃珍贵灵药惹祸，需宿主不断为其擦屁股。" },
                { name: "九龙拉棺", desc: "开局被传送到灵气枯竭之地。虽有登天之路，但起步艰难，需花费数倍于常人的努力才能走出废弃星域。" },
                { name: "键盘侠道", desc: "口诛笔伐，只能乱人道心。遇到听不懂人话的凶兽或心如磐石的魔修，毫无还手之力。" },
                { name: "退婚流", desc: "遭遇退婚羞辱，心魔滋生。戒指里的老爷爷苏醒前会不断吸取宿主修为，导致境界长期停滞不前。" },
                { name: "我的宗主父亲", desc: "虽背景深厚，但被卷入宗门权力斗争。父亲的政敌视你为眼中钉，时刻面临暗杀与陷害。" },
                { name: "扫地僧", desc: "身份低微，资源匮乏。虽有悟性，但无名师指点，且需完成繁重杂役，修炼" },
                { name: "炸天帮众", desc: "行事乖张，由于组织松散，在外惹祸后往往无人撑腰。且喜欢抄家底的作风极易引起公愤，遭群起攻之。" },
                { name: "科学修仙", desc: "离经叛道，不被传统修仙界接纳。研究过程充满爆炸风险，且所需材料多为稀奇古怪之物，难以收集。" },
                { name: "我儿有大帝之姿", desc: "自身资质平平，全靠子嗣争气。但若子嗣中途夭折或心生反骨，自身将失去所有依仗，晚景凄凉。" },
                { name: "未婚妻是女帝", desc: "未婚妻是转世女帝，但记忆严重错乱。她时常将你认作前世的死敌，在“爱侣”与“仇杀”状态间随机切换。你永远不知道下一刻醒来，面对的是温柔还是绝杀。" },
                { name: "复活甲", desc: "拥有一次复活机会，但复活后修为跌落，且随机传送。若运气不好重生在险地，便是刚出虎口又入狼窝。" },
                { name: "百分百空手接白刃", desc: "被动防御神技，但只能接剑。面对刀枪棍棒或法术轰炸时毫无作用，且接刃期间身体无法移动。" },
                { name: "恐怖如斯", desc: "因造成全球变暖被天道针对，渡劫难度倍增。且经常因为吸凉气而导致肺部受损，体质虚弱。" },
                { name: "位面之子", desc: "气运起伏不定，福祸相依。获得大机缘的同时必伴随大恐怖，每一次提升都是在生死边缘反复横跳。" },
                { name: "种田流", desc: "虽富甲一方，但战力低下。在强者为尊的世界，如同抱着金砖的孩童，是魔修和强盗眼中的最佳肥羊。" },
                { name: "召唤流", desc: "自身孱弱，全靠召唤物作战。一旦被敌人近身或切断与召唤物的联系，便只能任人宰割。" },
                { name: "天煞孤星", desc: "命犯天煞，注定孤独一生。克父克母克妻克子，虽自身气运极强，往往逢凶化吉，但身边亲近之人皆不得善终，注定独自登上大道之巅。" },
                { name: "绝世炉鼎", desc: "体质特殊，元阴/元阳极度纯净。虽修行速度一日千里，但不仅战力平平，且在所有高阶修士眼中皆是行走的无上补药，时刻面临被抓去采补的风险。" },
                { name: "厄难毒体", desc: "天生带毒，触之即死。虽能驾驭万毒，修为随毒性增长，但所过之处生灵涂炭，无人敢近身三尺，终将被正道视为异端邪魔，群起而攻之。" },
                { name: "九阳绝脉", desc: "体内阳气过盛，经脉如同烈火焚烧。若无极寒之物或纯阴体质调和，活不过二十岁。修行如在刀尖起舞，稍有不慎便引火自焚。" },
                { name: "九阴绝脉", desc: "体内阴气淤积，血液几近凝固。常年手脚冰凉，需不断吸纳阳气续命。虽适合修炼极阴功法，但极易被心魔入侵，沦为只知杀戮的冰冷兵器。" },
                { name: "贪狼入命", desc: "性情贪婪多疑，唯利是图。虽擅长在险境中攫取机缘，但因背信弃义而声名狼藉。身边无一可信之人，终日活在被昔日盟友背刺的恐惧中。" },
                { name: "桃花劫", desc: "容貌绝世，异性缘极佳，却总是烂桃花。所遇道侣非疯即魔，或因争风吃醋引发宗门大战，红颜祸水/蓝颜薄命，情关难过，大道难成。" },
                { name: "剑痴", desc: "爱剑成痴，除了练剑对万事万物漠不关心。虽剑道天赋绝顶，但人情世故一窍不通，极易得罪权贵。且无剑在手时，战力十不存一。" },
                { name: "路痴", desc: "对空间方位毫无感知。虽机缘巧合下可能误入上古秘境，但更多时候是在自家宗门迷路，或在被追杀时跑进死胡同，错失最佳逃生路线。" },
                { name: "非酋附体", desc: "气运极差，喝凉水都塞牙。探索秘境必遇空箱，炼丹必炸炉，渡劫必遇最强雷劫。想要变强，唯有付出别人百倍的努力和准备。" },
                { name: "招黑体质", desc: "哪怕什么都不做，也会莫名其妙拉满仇恨值。路过的魔头想随手拍死你，正道大能觉得你面目可憎。举世皆敌，只能在追杀中狼狈成长。" },
                { name: "走火入魔", desc: "心境不稳，极易受到情绪波动影响。战斗中虽能爆发超越极限的力量，但由于理智丧失，往往敌我不分，醒来后还要面对经脉受损的惨痛代价。" },
                { name: "枯荣之身", desc: "施展强力神通需燃烧寿元。虽能瞬间拥有越阶战力，但每次出手都是在透支生命。若无法寻得延寿圣药，未等成仙，人已老死。" },
                { name: "饕餮之胃", desc: "每日需摄入海量高阶灵食，否则修为倒退。在资源匮乏的修仙界，为了填饱肚子不得不四处掠夺，最终可能因贪吃而误食诱饵或毒物。" },
                { name: "睡梦罗汉", desc: "唯有在深度睡眠中才能高效修炼。清醒时浑浑噩噩，反应迟钝。且在闭关沉睡时毫无防备，极易被仇家摸进洞府一锅端。" },
                { name: "千面魔影", desc: "没有固定容貌，连自己都忘了本来面目。虽擅长伪装潜伏，但灵魂因频繁切换身份而分裂。常在关键时刻因认知错乱而露出破绽。" },
                { name: "暗夜行者", desc: "只能在黑夜中发挥全部实力，白昼时战力大减，且厌恶阳光。如同阴沟里的老鼠，无法在光天化日之下扬名立万，只能做个见不得光的刺客。" },
                { name: "五行缺钱", desc: "命格奇特，存不住灵石。无论获得多少机缘财富，总会因为各种意外（如法宝损坏、被人讹诈）而瞬间散尽，永远在贫困线上挣扎。" },
                { name: "灵兽憎恶", desc: "天生散发让妖兽厌恶的气息。进入山林必遭兽潮围攻，无法驯服任何灵宠。在依赖坐骑和战宠的修仙界，只能靠两条腿跑路。" },
                { name: "丹毒缠身", desc: "曾因急于求成吞服过量废丹，体内积蓄大量丹毒。虽对大多数毒药免疫，但每隔一段时间便会毒发，痛苦万分，且修为瓶颈比常人更难突破。" },
                { name: "恶灵附体", desc: "随身携带一把产生灵智的魔兵，器灵时刻想要夺舍宿主。虽能借用魔兵之力大杀四方，但精神时刻处于紧绷状态，稍有松懈便会万劫不复。" },
                { name: "残魂转世", desc: "灵魂残缺不全，记忆破碎。时常陷入突如其来的昏迷或失忆。且由于魂魄不全，无法修习高深的神魂防御功法，极易被精神攻击秒杀。" },
                { name: "天妒英才", desc: "悟性极高，任何功法一学就会，但因此遭天道忌惮。每逢大境界突破，雷劫威力倍增，且伴随心魔劫。稍有差池，便是身死道消。" },
                { name: "闭口禅", desc: "修习特殊功法，一旦开口说话破戒，多年苦修毁于一旦。无法通过言语交流，无法吟唱咒语，在需要沟通或辩解的场合极度吃亏。" },
                { name: "心眼皆盲", desc: "双目失明，虽练就神识探路，但面对针对神识的幻阵或屏蔽手段时，便如同待宰羔羊。且无法欣赏世间美色，道心易偏向孤僻冷漠。" },
                { name: "跛足道人", desc: "腿脚不便，身法笨拙。在讲究速度与机动的斗法中极为被动，只能修炼硬桥硬马的防御反击流派，打不赢也跑不掉。" },
                { name: "断臂求生", desc: "曾遭遇强敌断去一臂，虽勉强续命，但经脉不通，诸多双手结印的高阶术法无法施展。身体残缺导致大道不全，飞升艰难。" },
                { name: "寒毒入体", desc: "曾深入极寒之地受创，寒毒深入骨髓。每逢阴雨天便如坠冰窟，战力大减。需常年服用火系灵丹压制，是一笔巨大的开销。" },
