            // ===== 自定义选择模式（查看所有气运） =====
            let customSelectedEntries = [];

            function restoreSelectedEntriesFromDisplay() {
                const text = fortuneNameDisplay.textContent.trim();
                if (!text) return [];
                const allPools = [...trueFortunePresets, ...restrictedFortunePresets, ...allEroPresets];
                const entries = [];
                const matches = text.match(/【([^】]+)】/g);
                if (!matches) return [];
                matches.forEach(match => {
                    const name = match.replace(/【|】/g, '');
                    const found = allPools.find(p => p.name === name);
                    if (found && !entries.some(e => e.name === found.name)) {
                        entries.push({ name: found.name, desc: found.desc });
                    }
                });
                return entries;
            }

            function syncFortuneDisplay() {
                const names = customSelectedEntries.map(e => '【' + e.name + '】').join(' & ');
                const descs = customSelectedEntries.map(e => e.desc).join('\n\n');
                fortuneNameDisplay.textContent = names;
                fortuneInput.value = descs;
                renderSelectedTags();
                syncAllFortunesToMvu();
            }

            function renderSelectedTags() {
                fortuneTagsScroll.innerHTML = '';
                if (customSelectedEntries.length === 0) {
                    selectedFortuneTags.style.display = 'none';
                    return;
                }
                selectedFortuneTags.style.display = 'block';
                customSelectedEntries.forEach((entry, index) => {
                    const tag = document.createElement('span');
                    tag.className = 'fortune-tag';
                    tag.innerHTML = `${entry.name} <span class="remove-tag" data-index="${index}">×</span>`;
                    fortuneTagsScroll.appendChild(tag);
                });
                fortuneTagsScroll.querySelectorAll('.remove-tag').forEach(btn => {
                    btn.addEventListener('click', (e) => {
                        const idx = parseInt(e.target.dataset.index);
                        const removed = customSelectedEntries[idx];
                        customSelectedEntries.splice(idx, 1);
                        document.querySelectorAll('.custom-select-entry').forEach(el => {
                            if (el.dataset.name === removed.name) el.classList.remove('selected');
                        });
                        syncFortuneDisplay();
                    });
                });
            }

            function populateGrid(grid, pool, cssClass) {
                grid.innerHTML = '';
                pool.forEach((entry) => {
                    const btn = document.createElement('button');
                    btn.type = 'button';
                    btn.className = 'custom-select-entry ' + (cssClass || '');
                    btn.textContent = entry.name;
                    btn.title = entry.desc;
                    btn.dataset.name = entry.name;
                    btn.dataset.desc = entry.desc;
                    if (customSelectedEntries.some(e => e.name === entry.name)) {
                        btn.classList.add('selected');
                    }

                    let longPressTimer = null;
                    let isLongPress = false;
                    const startLongPress = (e) => {
                        isLongPress = false;
                        longPressTimer = setTimeout(() => {
                            isLongPress = true;
                            showEntryTooltip(entry.desc, btn);
                        }, 400);
                    };
                    const cancelLongPress = () => {
                        if (longPressTimer) { clearTimeout(longPressTimer); longPressTimer = null; }
                        hideEntryTooltip();
                    };

                    btn.addEventListener('touchstart', startLongPress, { passive: true });
                    btn.addEventListener('touchend', cancelLongPress, { passive: true });
                    btn.addEventListener('touchmove', cancelLongPress, { passive: true });
                    btn.addEventListener('mousedown', startLongPress);
                    btn.addEventListener('mouseup', cancelLongPress);
                    btn.addEventListener('mouseleave', cancelLongPress);

                    btn.addEventListener('click', (e) => {
                        if (isLongPress) {
                            e.preventDefault();
                            e.stopPropagation();
                            isLongPress = false;
                            return;
                        }
                        if (btn.classList.contains('selected')) {
                            btn.classList.remove('selected');
                            customSelectedEntries = customSelectedEntries.filter(e => e.name !== entry.name);
                        } else {
                            btn.classList.add('selected');
                            customSelectedEntries.push({ name: entry.name, desc: entry.desc });
                        }
                        syncFortuneDisplay();
                    });
                    grid.appendChild(btn);
                });
            }

