            function showDaoyuanLetter(onConfirm) {
                // 重置滚动位置
                daoyuanLetterBody.scrollTop = 0;
                // 重置按钮
                daoyuanLetterConfirm.classList.remove('ready');
                daoyuanLetterConfirm.textContent = '请先阅读全文 (10s)';
                daoyuanLetterHint.textContent = '▼ 请滑动阅读全文，10秒后可确认 ▼';
                daoyuanLetterOverlay.style.display = 'flex';

                var countdown = 10;
                var countdownDone = false;
                var scrolledDown = false;

                function tryUnlock() {
                    if (countdownDone && scrolledDown && !daoyuanLetterConfirm.classList.contains('ready')) {
                        daoyuanLetterConfirm.classList.add('ready');
                        daoyuanLetterConfirm.textContent = '原来如此！贩子司马！';
                        daoyuanLetterHint.textContent = '点击继续进入下一步';
                    }
                }

                // 10秒倒计时
                var timer = setInterval(function() {
                    countdown--;
                    if (countdown <= 0) {
                        countdownDone = true;
                        clearInterval(timer);
                        tryUnlock();
                    } else {
                        daoyuanLetterConfirm.textContent = '请先阅读全文 (' + countdown + 's)';
                    }
                }, 1000);

                // 滚动到底部也算读完
                daoyuanLetterBody.onscroll = function() {
                    var nearBottom = daoyuanLetterBody.scrollTop + daoyuanLetterBody.clientHeight >= daoyuanLetterBody.scrollHeight - 3;
                    if (nearBottom && !scrolledDown) {
                        scrolledDown = true;
                        tryUnlock();
                        if (!daoyuanLetterConfirm.classList.contains('ready')) {
                            daoyuanLetterHint.textContent = '▼ 已阅读完毕，请等待倒计时结束 ▼';
                        }
                    }
                };

                // 确认按钮
                daoyuanLetterConfirm.onclick = function() {
                    if (!daoyuanLetterConfirm.classList.contains('ready')) return;
                    daoyuanLetterOverlay.style.display = 'none';
                    clearInterval(timer);
                    daoyuanLetterBody.onscroll = null;
                    if (onConfirm) onConfirm();
                };
            }
