                }

                setTimeout(() => {
                    fortuneSelectionContainer.innerHTML = '';
                    fortuneSelectionContainer.style.display = 'flex';

                    let currentDisplayName = "";
                    let currentDisplayDesc = "";

                    const generatedButtons = [];
                    const selectedNames = new Set();

                    const generateButtonsFromPool = (pool, count, isEroType, lockedItem = null) => {
                        let drawCount = count;

                        if (lockedItem) {
                            generatedButtons.push(lockedItem);
                            selectedNames.add(lockedItem.data.name);
                            drawCount--;
                        }

                        const availableIndices = Array.from({length: pool.length}, (_, i) => i);
                        let generatedCount = 0;

                        while (generatedCount < drawCount && availableIndices.length > 0) {
                            const randIndexPos = Math.floor(Math.random() * availableIndices.length);
                            const index = availableIndices.splice(randIndexPos, 1)[0];
                            let fortuneData = pool[index];
                            let isTrueFortune = false;

                            if (!isEroType && isCheatEnabled) {
                                if (Math.random() < 0.05 && index < trueFortunePresets.length) {
                                    fortuneData = trueFortunePresets[index];
                                    isTrueFortune = true;
                                } else {
                                    if(index < restrictedFortunePresets.length) {
                                         fortuneData = restrictedFortunePresets[index];
                                    }
                                }
                            } else if (!isEroType && currentMode === 'hard') {
                                if(index < restrictedFortunePresets.length) {
                                    fortuneData = restrictedFortunePresets[index];
                                }
                            }

                             if (!selectedNames.has(fortuneData.name)) {
                                selectedNames.add(fortuneData.name);
                                generatedButtons.push({
                                    data: fortuneData,
                                    isTrue: isTrueFortune,
                                    isEro: isEroType,
                                    type: isEroType ? 'ero' : 'normal'
                                });
                                generatedCount++;
                            }
                        }
                    };

                    if (isEroMode) {
                        generateButtonsFromPool(restrictedFortunePresets, 5, false, lockedNormal);
                        const gender = genderInput.value.trim();
                        const isHeavyMode = heavyToggle.checked;
                        let eroPool;
                        if (/女|女性|雌|雌性/.test(gender)) {
                            eroPool = [...femaleEroPresets, ...neutralEroPresets];
                        } else if (/男|男性|雄|雄性/.test(gender)) {
                            eroPool = [...maleEroPresets, ...neutralEroPresets];
                        } else {
                            eroPool = allEroPresets;
                        }
                        if (isHeavyMode) {
                            if (/女|女性|雌|雌性/.test(gender)) {
                                eroPool = [...eroPool, ...heavyEroFemalePresets];
                            } else if (/男|男性|雄|雄性/.test(gender)) {
                                eroPool = [...eroPool, ...heavyEroPresets];
                            } else {
                                eroPool = [...eroPool, ...heavyEroPresets, ...heavyEroFemalePresets];
                            }
                        }
                        generateButtonsFromPool(eroPool, 5, true, lockedEro);
                    } else {
                        const drawCount = currentMode === 'hard' ? 5 : 10;
                        generateButtonsFromPool(restrictedFortunePresets, drawCount, false, lockedNormal);
                    }

                    generatedButtons.forEach(item => {
                        const btn = document.createElement('button');
                        let className = 'preset-btn';
                        if (item.isTrue) className += ' true-fortune';
                        if (item.isEro) className += ' ero-fortune';

                        if ((lockedNormal && item.data.name === lockedNormal.data.name) ||
                            (lockedEro && item.data.name === lockedEro.data.name)) {
                            className += ' selected';

                            if (item.type === 'normal') {
                                currentDisplayName += `【${item.data.name}】`;
                                currentDisplayDesc = item.data.desc + currentDisplayDesc;
                            } else {
                                if (currentDisplayName) currentDisplayName += ` & `;
                                currentDisplayName += `【${item.data.name}】`;
                                if (currentDisplayDesc) currentDisplayDesc += "\n\n[合欢]: ";
                                currentDisplayDesc += item.data.desc;
                            }
                        }

                        btn.type = 'button';
                        btn.className = className;
                        btn.textContent = item.data.name;
                        btn.dataset.name = item.data.name;
                        btn.dataset.desc = item.data.desc;
                        btn.dataset.type = item.type;
                        btn.title = item.data.desc;
                        fortuneSelectionContainer.appendChild(btn);
                    });

                    fortuneNameDisplay.textContent = currentDisplayName;
                    fortuneInput.value = currentDisplayDesc;

                    syncAllFortunesToMvu();

                    if (currentMode === 'hard' || currentMode === 'normal') {
                        fortuneRollsLeft--;
                        drawFortuneBtn.textContent = fortuneRollsLeft > 0 ? `再算一次 (${fortuneRollsLeft})` : '天机已泄';
                        drawFortuneBtn.disabled = fortuneRollsLeft <= 0;
                    } else {
                        drawFortuneBtn.textContent = '再算一次';
                        drawFortuneBtn.disabled = false;
                    }
                }, 800);
            });

            // 修改点：支持再次点击解锁
            fortuneSelectionContainer.addEventListener('click', (e) => {
                if (e.target.tagName === 'BUTTON' && e.target.classList.contains('preset-btn')) {
                    const isEroMode = eroToggle.checked;
                    const clickedType = e.target.dataset.type;
                    const isAlreadySelected = e.target.classList.contains('selected');

                    if (isEroMode) {
                        const siblings = fortuneSelectionContainer.querySelectorAll(`.preset-btn[data-type="${clickedType}"]`);
                        siblings.forEach(btn => btn.classList.remove('selected'));

                        if (!isAlreadySelected) {
                            e.target.classList.add('selected');
                        }

                        const selectedNormal = fortuneSelectionContainer.querySelector('.preset-btn.selected[data-type="normal"]');
                        const selectedEro = fortuneSelectionContainer.querySelector('.preset-btn.selected[data-type="ero"]');

                        let displayName = "";
                        let displayDesc = "";

                        if (selectedNormal) {
                            displayName += `【${selectedNormal.dataset.name}】`;
                            displayDesc += `${selectedNormal.dataset.desc}`;
                        }
                        if (selectedEro) {
                            if (displayName) displayName += ` & `;
                            displayName += `【${selectedEro.dataset.name}】`;
                            if (displayDesc) displayDesc += "\n\n[合欢]: ";
                            displayDesc += `${selectedEro.dataset.desc}`;
                        }

                        fortuneNameDisplay.textContent = displayName;
                        fortuneInput.value = displayDesc;
                        syncAllFortunesToMvu();

                    } else {
                        const allBtns = fortuneSelectionContainer.querySelectorAll('.preset-btn');
                        allBtns.forEach(btn => btn.classList.remove('selected'));

                        if (!isAlreadySelected) {
                            e.target.classList.add('selected');
                            const { name, desc } = e.target.dataset;
                            fortuneNameDisplay.textContent = `【${name}】`;
                            fortuneInput.value = desc;
                        } else {
                            fortuneNameDisplay.textContent = ``;
                            fortuneInput.value = ``;
                        }
                        syncAllFortunesToMvu();
                    }
                }
            });

            const particleContainer = document.getElementById('background-particles');
            const numParticles = 40;
            for (let i = 0; i < numParticles; i++) {
                let particle = document.createElement('div');
                particle.className = 'particle';
                let size = Math.random() * 4 + 1.5;
                particle.style.width = `${size}px`;
                particle.style.height = `${size}px`;
                particle.style.left = `${Math.random() * 100}%`;
                particle.style.animationDelay = `${Math.random() * 25}s`;
                particle.style.animationDuration = `${Math.random() * 20 + 15}s`;
                if(Math.random() > 0.8) {
                    particle.style.backgroundColor = 'var(--gold-color)';
                     particle.style.boxShadow = '0 0 8px var(--gold-color)';
                }
                particleContainer.appendChild(particle);
            }

            function transitionToCreation(mode) {
                currentMode = mode;
                sessionStorage.removeItem(CUSTOM_FORTUNE_AUTH_KEY);

                customFortuneSection.style.display = 'block';
                companionSection.style.display = 'block';
                realmInput.style.display = 'block';
                realmSelect.style.display = 'none';
                realmInput.disabled = false;
                spiritRootTextarea.style.display = 'block';
                hardModeSpiritRootSection.style.display = 'none';
                realmInput.value = "";

                eroToggle.checked = false;
                heavyToggle.checked = false;
                eroSubOptions.classList.remove('visible');
                customSelectPanel.classList.remove('active');
                fortuneSelectionContainer.style.display = 'none';
                browseAllBtn.textContent = '📖 查看所有气运';
                browseAllBtn.style.display = 'none';
                customFortuneToggle.checked = false;
                customFortuneDivider.style.display = 'none';
                customFortuneToggle.closest('.toggle-group').style.display = 'none';
                drawFortuneBtn.textContent = '天机演算，抽取气运';
                // === 修复bug：重置灵根抽取状态 ===
                rollSpiritRootBtn.disabled = false;
                spiritRootResult.textContent = "尚未觉醒...";
                spiritRootResult.className = "gacha-display";
                hardModeSpiritRootValue = "";
                // =================================

                // === 修复bug：重置气运抽取状态 ===
                fortuneSelectionContainer.style.display = 'none';
                fortuneSelectionContainer.innerHTML = '';
                fortuneNameDisplay.textContent = '';
                fortuneInput.value = '';
                // =================================

                if (mode === 'hard') {
                    cheatToggleSection.style.display = 'none';
                    cheatToggle.checked = false;
                } else {
                    cheatToggleSection.style.display = 'flex';
                }

                if (mode === 'simple') {
                    customFortuneSection.style.display = 'block';
                    realmInput.disabled = false;
                    spiritRootTextarea.style.display = 'block';
                    hardModeSpiritRootSection.style.display = 'none';
                    customFortuneDivider.style.display = 'inline-block';
                    customFortuneToggle.closest('.toggle-group').style.display = 'flex';

                } else if (mode === 'normal') {
                    customFortuneSection.style.display = 'none';
                    spiritRootTextarea.style.display = 'none';
                    hardModeSpiritRootSection.style.display = 'block';
                    spiritRootRollsLeft = 10;
                    fortuneRollsLeft = 10;
                    rollSpiritRootBtn.textContent = `灵根觉醒 (剩余次数: ${spiritRootRollsLeft})`;
                    drawFortuneBtn.textContent = "天机演算，抽取气运";
                    drawFortuneBtn.disabled = false;
                    companionSection.style.display = 'none';
                    realmInput.style.display = 'none';
                    realmSelect.style.display = 'block';

                } else if (mode === 'hard') {
                    customFortuneSection.style.display = 'none';
                    companionSection.style.display = 'none';
                    realmInput.value = "未修炼";
                    realmInput.disabled = true;
                    spiritRootTextarea.style.display = 'none';
                    hardModeSpiritRootSection.style.display = 'block';
                    spiritRootRollsLeft = 3;
                    fortuneRollsLeft = 5;
                    rollSpiritRootBtn.textContent = "灵根觉醒 (剩余次数: 3)";
                    drawFortuneBtn.textContent = "天机演算，抽取气运";
                    drawFortuneBtn.disabled = false;
                }

                startScreen.classList.remove('active');
                setTimeout(() => creationScreen.classList.add('active'), 500);
            }

            startButton.addEventListener('click', () => {
                startButton.style.display = 'none';
                initialWarning.style.display = 'none';
                modeSelection.classList.add('visible');
            });

            simpleModeBtn.addEventListener('click', () => transitionToCreation('simple'));
            normalModeBtn.addEventListener('click', () => transitionToCreation('normal'));
            hardModeBtn.addEventListener('click', () => transitionToCreation('hard'));

            confirmButton.addEventListener('click', async () => {
                let finalSpiritRoot = spiritRootTextarea.value.trim();
                let finalRealm;

                if (currentMode === 'normal') {
                    finalRealm = realmSelect.value;
                } else {
                    finalRealm = realmInput.value.trim();
                }

                if (currentMode === 'hard' || currentMode === 'normal') {
                    if (!hardModeSpiritRootValue) {
                         alert("修仙本逆天而行，汝连灵根都未觉醒，如何踏上仙途？(请抽取灵根)");
                         return;
                    }
                    finalSpiritRoot = hardModeSpiritRootValue;

                    if (currentMode === 'hard') {
                        finalRealm = "未修炼";
                    }
                }

                const customFortunes = getCustomFortuneEntries();

                let combinedFortune;
                if (currentMode === 'simple' && customFortunes.length > 0) {
                    combinedFortune = customFortunes.map(c => `【${c.name}】 ${c.desc}`).join('\n');
                } else {
                    const fn = fortuneNameDisplay.textContent.trim().replace(/【|】/g, '');
                    const fd = fortuneInput.value.trim();
                    combinedFortune = fn ? `【${fn}】 ${fd}` : fd;
                }
                if (!combinedFortune || !combinedFortune.trim()) {
                    combinedFortune = '无';
                }

                const characterData = {
                    name: nameInput.value.trim(),
                    gender: genderInput.value.trim(),
                    race: raceInput.value.trim(),
                    appearance: appearanceInput.value.trim(),
                    realm: finalRealm,
                    identity: identityInput.value.trim(),
                    spiritRoot: finalSpiritRoot,
                    technique: techniqueTextarea.value.trim(),
                    fortune: combinedFortune
                };

                const companionData = {
                    name: companionNameInput.value.trim(),
                    gender: companionGenderInput.value.trim(),
                    appearance: companionAppearanceInput.value.trim(),
                    clothing: companionClothingInput.value.trim(),
                    race: companionRaceInput.value.trim(),
                    class: companionClassInput.value.trim(),
                    personality: companionPersonalityInput.value.trim(),
                    age: companionAgeInput.value.trim(),
                    abilities: companionAbilitiesTextarea.value.trim(),
                    backstory: companionBackstoryTextarea.value.trim()
                };

                if (!characterData.name) {
                    nameInput.style.borderColor = 'var(--accent-blue)';
                    nameInput.placeholder = '道号不可为空！';
                    setTimeout(() => {
                       nameInput.style.borderColor = 'var(--input-border)';
                       nameInput.placeholder = '你的名讳或道号';
                    }, 2000);
                    return;
                }

                // --- 世界书注入逻辑整合 ---
                try {
                    if (typeof getLorebooks === 'function' && typeof createLorebook === 'function' && typeof createLorebookEntry === 'function') {
                        const lorebookName = "道渊开局创建人物";
                        const lorebooks = await getLorebooks();
                        if (!lorebooks.includes(lorebookName)) {
                            await createLorebook(lorebookName);
                        }

                        const entriesToCreate = [];
                        const defaultEntryProps = {
                            type: 'constant', // 蓝灯常驻
                            position: 'before_character_definition',
                            order: 100,
                            exclude_recursion: true,
                            prevent_recursion: true
                        };

                        if (characterData.technique) {
                            entriesToCreate.push({
                                ...defaultEntryProps,
                                comment: `${characterData.name}-功法设定`,
                                content: `【${characterData.name}的主修功法】：${characterData.technique}`
                            });
                        }
                        if (characterData.fortune && characterData.fortune !== '无') {
                            entriesToCreate.push({
                                ...defaultEntryProps,
                                comment: `${characterData.name}-气运命格`,
                                content: `【${characterData.name}的天道气运】：${characterData.fortune}`
                            });
                        }

                        if (currentMode !== 'hard' && currentMode !== 'normal' && companionSection.style.display !== 'none' && companionData.name) {
                            let companionStr = `【user的天定道侣-${companionData.name}】\n`;
                            if (companionData.gender) companionStr += `性别: ${companionData.gender} | `;
                            if (companionData.race) companionStr += `种族: ${companionData.race} | `;
                            if (companionData.class) companionStr += `修为: ${companionData.class} | `;
                            if (companionData.age) companionStr += `年龄: ${companionData.age}\n`;
                            if (companionData.appearance) companionStr += `容貌: ${companionData.appearance}\n`;
                            if (companionData.clothing) companionStr += `衣着: ${companionData.clothing}\n`;
                            if (companionData.personality) companionStr += `性情: ${companionData.personality}\n`;
                            if (companionData.abilities) companionStr += `功法能力: ${companionData.abilities}\n`;
                            if (companionData.backstory) companionStr += `羁绊渊源: ${companionData.backstory}`;

                            entriesToCreate.push({
                                ...defaultEntryProps,
                                comment: `天命道侣-${companionData.name}`,
                                content: companionStr.trim()
                            });
                        }

                        // 将封装好的数据依次注入
                        for (const entry of entriesToCreate) {
                            await createLorebookEntry(lorebookName, entry);
                        }
                        console.log("「道渊开局创建人物」世界书信息注入成功！");
                    } else {
                        console.warn("当前环境检测不到酒馆世界书API，如果是测试状态可忽略，请在SillyTavern扩展中运行。");
                    }
                } catch (err) {
                    console.error("世界书生成时发生异常错误:", err);
                }
                // --- 世界书注入逻辑完毕 ---

                // --- MVU 数据同步 ---
                try {
                    if (mvuReady) {
                        const msgId = getCurrentMessageId();
                        const data = Mvu.getMvuData({type: 'message', message_id: msgId});
                        if (data && data.stat_data) {
                            _.set(data, 'stat_data.主角.境界', characterData.realm || '凡人（DC:0）');
                            _.set(data, 'stat_data.主角.灵根', characterData.spiritRoot || '未知');
                            _.set(data, 'stat_data.主角.状态', '无异常');
                            _.set(data, 'stat_data.主角.生命', 100);
                            _.set(data, 'stat_data.主角.精血', 100);
                            _.set(data, 'stat_data.主角.灵力', 100);
                            _.set(data, 'stat_data.主角.修为', 0);
                            _.set(data, 'stat_data.主角.神识', 100);
                            _.set(data, 'stat_data.主角.道心', 50);
                            _.set(data, 'stat_data.主角.神念', '无');
                            _.set(data, 'stat_data.主角.宗门', '无');
                            _.set(data, 'stat_data.主角.所在界', '玄天界');

                            _.set(data, 'stat_data.主角.炼丹', { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 });
                            _.set(data, 'stat_data.主角.炼器', { 阶级: '未入门', 熟练度: 0, 成功率: 0, 次数: 0 });
                            _.set(data, 'stat_data.主角.储物袋', {});
                            _.set(data, 'stat_data.主角.器物', {});

                            // 多条目气运
                            const fortuneEntries = resolveFortuneEntries();
                            const qiyun = {};
                            fortuneEntries.forEach(e => {
                                qiyun[e.name] = { 类型: '被动', 效果: e.desc, 使用状态: '常驻', 剩余次数: null, 压制状态: '正常' };
                            });
                            _.set(data, 'stat_data.主角.气运', qiyun);

                            // 世界初始变量
                            _.set(data, 'stat_data.世界', {
                                当前时间: '未知',
                                当前地点: '未知',
                                危机程度: '无',
                                动向: {}
                            });

                            // 其他初始空变量
                            _.set(data, 'stat_data.灵宠', {});
                            _.set(data, 'stat_data.人物', {});
                            _.set(data, 'stat_data.机遇', {});
                            _.set(data, 'stat_data.绝色榜', {});
                            _.set(data, 'stat_data.玉简', {});

                            if (currentMode !== 'hard' && currentMode !== 'normal' && companionSection.style.display !== 'none' && companionData.name) {
                                const existingDaoLv = _.get(data, 'stat_data.道侣', {});
                                existingDaoLv[companionData.name] = {
                                    种族: companionData.race || '人族',
                                    状态: '正常',
                                    境界: companionData.class || '未知',
                                    亲密: 100,
                                    生命: 100,
                                    灵力: 100,
                                    修为: 0,
                                    道心: 50,
                                    性格: companionData.personality || '未知',
                                    外观: companionData.appearance || '未知',
                                    身高: '未知',
                                    背景: companionData.backstory || '',
                                    神通: companionData.abilities || '无',
                                    心声: '无'
                                };
                                _.set(data, 'stat_data.道侣', existingDaoLv);
                            }

                            await Mvu.replaceMvuData(data, {type: 'message', message_id: msgId});
                            console.log('[道渊创建] MVU同步成功');
                        }
                    }
                } catch (err) {
                    console.error('[道渊创建] MVU同步失败:', err);
                }
                // --- MVU 数据同步完毕 ---

                                document.body.innerHTML = '<div style="display:flex; justify-content:center; align-items:center; height:100vh;"><h1 class="title" style="animation: none; opacity: 1;">...仙途已启...</h1></div>';

                let sysMessage = `/sys [仙缘已定 - ${currentMode === 'hard' ? '困难模式' : (currentMode === 'normal' ? '普通模式' : '简单模式')}]\n**道号**: ${characterData.name}\n**性别**: ${characterData.gender}\n**种族**: ${characterData.race}\n**容貌**: ${characterData.appearance}\n**境界**: ${characterData.realm}\n**出身**: ${characterData.identity}\n**出生地**: 玄天界\n**灵根**: ${characterData.spiritRoot || '无'}\n**功法**: ${characterData.technique || '无'}\n**气运**: ${characterData.fortune}`;

                if (currentMode !== 'hard' && currentMode !== 'normal' && companionSection.style.display !== 'none' && companionData.name) {
                    sysMessage += `\n\n[天定道侣]\n**姓名**: ${companionData.name}\n**性别**: ${companionData.gender}\n**容貌**: ${companionData.appearance}\n**衣着**: ${companionData.clothing}\n**种族/身份**: ${companionData.race}\n**境界/修为**: ${companionData.class}\n**性情**: ${companionData.personality}\n**年龄**: ${companionData.age}\n**功法/能力**: ${companionData.abilities}\n**与汝渊源**: ${companionData.backstory}`;
                }

                sysMessage += `\n\n[仙途开启中...]`;

                if (typeof triggerSlash === 'function' && typeof getCurrentMessageId === 'function') {
                    const currentMessageId = getCurrentMessageId();
                    // 改用完美的管道符串联命令：发送内容 -> 删除UI防占位 -> 触发AI
                    const startCommand = `${sysMessage} | /cut ${currentMessageId} | /trigger`;
                    triggerSlash(startCommand);
                } else {
                    console.log("无法触发SillyTavern命令，这是生成的命令:", `${sysMessage} | /trigger`);
                }
            });
        });
    </script>

